// ─────────────────────────────────────────────
// SERVICE LOGOS + ICONS
// ─────────────────────────────────────────────
const SERVICE_LOGOS = {
  snowflake: <svg viewBox="0 0 32 32" fill="none"><rect width="32" height="32" rx="6" fill="#29b5e8"/><path d="M16 6v20M6 16h20M9.2 9.2l13.6 13.6M22.8 9.2L9.2 22.8" stroke="white" strokeWidth="2" strokeLinecap="round"/></svg>,
  postgres:  <svg viewBox="0 0 32 32" fill="none"><rect width="32" height="32" rx="6" fill="#336791"/><text x="16" y="21" textAnchor="middle" fill="white" fontSize="9" fontWeight="700" fontFamily="monospace">PG</text></svg>,
  looker:    <svg viewBox="0 0 32 32" fill="none"><rect width="32" height="32" rx="6" fill="#4285f4"/><circle cx="14" cy="14" r="5" fill="none" stroke="white" strokeWidth="2"/><path d="M18 18l4 4" stroke="white" strokeWidth="2.5" strokeLinecap="round"/></svg>,
  tableau:   <svg viewBox="0 0 32 32" fill="none"><rect width="32" height="32" rx="6" fill="#1f77b4"/><path d="M16 8v16M8 16h16M11 11v10M21 11v10M8 13h16M8 19h16" stroke="white" strokeWidth="1.5" strokeLinecap="round"/></svg>,
  airflow:   <svg viewBox="0 0 32 32" fill="none"><rect width="32" height="32" rx="6" fill="#017cee"/><circle cx="10" cy="16" r="2.5" fill="white"/><circle cx="22" cy="10" r="2.5" fill="white"/><circle cx="22" cy="22" r="2.5" fill="white"/><path d="M12.5 15L19.5 11M12.5 17L19.5 21" stroke="white" strokeWidth="1.5" strokeLinecap="round"/></svg>,
  mlflow:    <svg viewBox="0 0 32 32" fill="none"><rect width="32" height="32" rx="6" fill="#0194e2"/><path d="M8 24l8-16 8 16" stroke="white" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" fill="none"/><path d="M11 18h10" stroke="white" strokeWidth="2" strokeLinecap="round"/></svg>,
  dbt:       <svg viewBox="0 0 32 32" fill="none"><rect width="32" height="32" rx="6" fill="#ff6f44"/><path d="M16 8l4 4-4 4-4-4 4-4z" fill="white" opacity=".3"/><path d="M16 12v8M12 16h8" stroke="white" strokeWidth="2" strokeLinecap="round"/></svg>,
  bigquery:  <svg viewBox="0 0 32 32" fill="none"><rect width="32" height="32" rx="6" fill="#4285f4"/><circle cx="14" cy="14" r="5" fill="none" stroke="white" strokeWidth="1.5" opacity=".5"/><circle cx="14" cy="14" r="2.5" fill="white"/><path d="M18 18l4 4" stroke="white" strokeWidth="2.5" strokeLinecap="round"/></svg>,
};

const ServiceIcon = ({service, size=18}) => {
  const logo = SERVICE_LOGOS[service];
  return (
    <div style={{width:size,height:size,borderRadius:size*0.2,overflow:"hidden",flexShrink:0,display:"flex"}}>
      {logo ? React.cloneElement(logo,{width:size,height:size}) : <div style={{width:size,height:size,background:T.bgHover,borderRadius:size*0.2}}/>}
    </div>
  );
};

const TierBadge = ({tier}) => {
  if(!tier) return null;
  const colors = {1:{bg:"rgba(238,36,36,.1)",color:"#ee2424",border:"rgba(238,36,36,.3)"},2:{bg:"rgba(217,119,6,.1)",color:"#d97706",border:"rgba(217,119,6,.3)"},3:{bg:"rgba(75,75,96,.1)",color:"#4b4b60",border:"rgba(75,75,96,.3)"}};
  const c = colors[tier]||colors[3];
  return <span style={{fontSize:10,fontWeight:700,padding:"1px 6px",borderRadius:4,background:c.bg,color:c.color,border:`1px solid ${c.border}`,letterSpacing:"0.03em"}}>T{tier}</span>;
};

// ─────────────────────────────────────────────
// UI PRIMITIVES
// ─────────────────────────────────────────────
const Badge = ({color,bg,border,children})=>(
  <span style={{display:"inline-flex",alignItems:"center",padding:"2px 8px",borderRadius:99,fontSize:11,fontWeight:600,background:bg||T.accentDim,color:color||T.accent,border:`1px solid ${border||T.accent+"33"}`,whiteSpace:"nowrap"}}>{children}</span>
);

const SDot = ({status})=>{
  const c = {passing:T.green,warning:T.amber,failing:T.rose,Active:T.accent,Draft:T.textSub,Pending:T.amber,Approved:T.accent,Denied:T.rose,Deprecated:T.rose,"In Progress":T.blue,"In Review":T.amber,"Open":T.textSub}[status]||T.textSub;
  return <span style={{display:"inline-block",width:6,height:6,borderRadius:"50%",background:c,flexShrink:0}}/>;
};

const TypeBadge = ({type})=>{
  const map = {Table:{c:"#38bdf8",bg:"rgba(56,189,248,.1)"},Dashboard:{c:"#a78bfa",bg:"rgba(167,139,250,.1)"},Pipeline:{c:"#34d399",bg:"rgba(52,211,153,.1)"},"ML Model":{c:"#fb923c",bg:"rgba(251,146,60,.1)"}};
  const s = map[type]||{c:T.textMuted,bg:T.bgHover};
  return <span style={{fontSize:10.5,fontWeight:600,padding:"2px 7px",borderRadius:4,background:s.bg,color:s.c,border:`1px solid ${s.c}22`}}>{type}</span>;
};

const CertBadge = ({cert})=>{
  const map = {
    Draft:       {c:"#6b7280", bg:"rgba(107,114,128,.1)"},
    "In Review": {c:"#d97706", bg:"rgba(217,119,6,.1)"},
    Approved:    {c:"#16a34a", bg:"rgba(22,163,74,.1)"},
    Rejected:    {c:"#e11d48", bg:"rgba(225,29,72,.1)"},
    Deprecated:  {c:"#7c3aed", bg:"rgba(124,58,237,.1)"},
  };
  const s = map[cert]||{c:T.textMuted,bg:T.bgHover};
  return <span style={{fontSize:10.5,fontWeight:600,padding:"2px 7px",borderRadius:4,background:s.bg,color:s.c}}>{cert||"Not Certified"}</span>;
};

const QScore = ({score})=>{
  const c = score>=90?"#16a34a":score>=70?"#d97706":"#dc2626";
  const bg = score>=90?"rgba(22,163,74,.1)":score>=70?"rgba(217,119,6,.1)":"rgba(220,38,38,.1)";
  return (
    <span style={{display:"inline-flex",alignItems:"center",gap:7}}>
      <span style={{position:"relative",display:"inline-block",width:48,height:5,borderRadius:3,background:T.bgHover,overflow:"hidden",flexShrink:0}}>
        <span style={{display:"block",width:`${score}%`,height:"100%",background:c,borderRadius:3,transition:"width .3s"}}/>
      </span>
      <span style={{fontSize:11,fontWeight:700,fontFamily:"'Geist Mono',monospace",color:c,background:bg,padding:"1px 5px",borderRadius:4,minWidth:28,textAlign:"center"}}>{score}</span>
    </span>
  );
};

const Btn = ({children,variant,ghost,small,icon,onClick,disabled})=>{
  const base = {display:"inline-flex",alignItems:"center",gap:5,padding:small?"4px 10px":"7px 14px",borderRadius:7,fontSize:small?11:12.5,fontWeight:600,cursor:disabled?"not-allowed":"pointer",border:"none",transition:"all .12s",opacity:disabled?.5:1,whiteSpace:"nowrap"};
  const styles = variant==="primary"?{...base,background:T.accent,color:"#fff"}:variant==="danger"?{...base,background:T.roseDim,color:T.rose,border:`1px solid ${T.rose}33`}:ghost?{...base,background:"transparent",color:T.textSub,border:`1px solid ${T.border}`}:{...base,background:T.bgElevated,color:T.text,border:`1px solid ${T.border}`};
  return <button style={styles} onClick={onClick} disabled={disabled}>{icon&&<span style={{display:"flex"}}>{icon}</span>}{children}</button>;
};

const Input2 = ({value,onChange,placeholder,icon,style,multiline,rows=3})=>{
  const s = {width:"100%",padding:"7px 10px 7px"+(icon?" 10px":" 10px"),background:T.bgElevated,border:`1px solid ${T.border}`,borderRadius:8,color:T.text,fontSize:12.5,outline:"none",...style};
  if(multiline) return <textarea value={value} onChange={onChange} placeholder={placeholder} rows={rows} style={{...s,resize:"vertical",fontFamily:"inherit",lineHeight:1.5}}/>;
  return (
    <div style={{position:"relative",width:"100%",...style}}>
      {icon&&<span style={{position:"absolute",left:9,top:"50%",transform:"translateY(-50%)",color:T.textMuted,display:"flex",pointerEvents:"none"}}>{icon}</span>}
      <input value={value} onChange={onChange} placeholder={placeholder} style={{...s,paddingLeft:icon?"30px":"10px",width:"100%",boxSizing:"border-box"}}
        onFocus={e=>e.target.style.borderColor=T.accent} onBlur={e=>e.target.style.borderColor=T.border}/>
    </div>
  );
};

const Card2 = ({children,style})=>(
  <div style={{background:T.bgSurface,border:`1px solid ${T.border}`,borderRadius:10,...style}}>{children}</div>
);

const DataTable = ({cols,rows,onRowClick,emptyMsg="No data"})=>(
  <div style={{background:T.bgSurface,border:`1px solid ${T.border}`,borderRadius:10,overflow:"hidden"}}>
    <div style={{overflowX:"auto"}}>
      {rows.length===0
        ? <div style={{padding:"40px 20px",textAlign:"center",color:T.textMuted,fontSize:13}}>{emptyMsg}</div>
        : <table style={{width:"100%",borderCollapse:"collapse"}}>
            <thead>
              <tr style={{background:T.bgElevated}}>
                {cols.map(c=><th key={c.key} style={{padding:"9px 14px",fontSize:10.5,fontWeight:600,color:T.textMuted,textAlign:"left",borderBottom:`1px solid ${T.border}`,whiteSpace:"nowrap",textTransform:"uppercase",letterSpacing:"0.07em"}}>{c.label}</th>)}
              </tr>
            </thead>
            <tbody>
              {rows.map((row,i)=>(
                <tr key={i} className={onRowClick?"row-hover":""} onClick={()=>onRowClick&&onRowClick(row)}
                  style={{borderBottom:i<rows.length-1?`1px solid ${T.border}`:"none",transition:"background .1s"}}>
                  {cols.map(c=><td key={c.key} style={{padding:"11px 14px",fontSize:12,color:T.text,verticalAlign:"middle"}}>{c.render?c.render(row[c.key],row):row[c.key]}</td>)}
                </tr>
              ))}
            </tbody>
          </table>}
    </div>
  </div>
);

const Modal = ({open,onClose,title,children,width=540})=>{
  if(!open)return null;
  return <div className="fadeIn" style={{position:"fixed",inset:0,zIndex:1000,background:"rgba(0,0,0,.7)",display:"flex",alignItems:"center",justifyContent:"center",padding:20}} onClick={onClose}>
    <div className="scaleIn" style={{background:T.bgSurface,border:`1px solid ${T.border}`,borderRadius:14,width:"100%",maxWidth:width,maxHeight:"90vh",overflow:"auto"}} onClick={e=>e.stopPropagation()}>
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"18px 22px",borderBottom:`1px solid ${T.border}`}}>
        <span style={{fontSize:14,fontWeight:600,color:T.text}}>{title}</span>
        <button onClick={onClose} style={{background:"transparent",border:"none",color:T.textMuted,cursor:"pointer",display:"flex"}}>{Ic.x(14)}</button>
      </div>
      <div style={{padding:22}}>{children}</div>
    </div>
  </div>;
};

const Toast = ({msg,type="success",onDone})=>{
  useEffect(()=>{const t=setTimeout(onDone,3000);return()=>clearTimeout(t);},[]);
  const c = type==="success"?T.accent:type==="error"?T.rose:T.amber;
  return <div className="slideIn" style={{position:"fixed",bottom:24,right:24,zIndex:2000,padding:"12px 18px",background:T.bgSurface,border:`1px solid ${c}44`,borderRadius:10,boxShadow:"0 8px 24px rgba(0,0,0,.3)",display:"flex",alignItems:"center",gap:10,fontSize:13,color:T.text,maxWidth:320}}>
    <span style={{width:8,height:8,borderRadius:"50%",background:c,flexShrink:0}}/>
    {msg}
  </div>;
};

const Topbar = ({breadcrumb,actions})=>{
  const {isDark,toggleTheme} = useTheme();
  return (
  <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"0 20px 0 24px",height:52,borderBottom:`1px solid ${T.border}`,background:T.bgSurface,flexShrink:0}}>
    {/* Left: breadcrumb */}
    <div style={{display:"flex",alignItems:"center",gap:6}}>
      {breadcrumb.map((b,i)=>(
        <React.Fragment key={i}>
          {i>0&&<span style={{color:T.textMuted,fontSize:12}}>/</span>}
          {b.onClick
            ? <button onClick={b.onClick} style={{background:"transparent",border:"none",color:T.textMuted,cursor:"pointer",fontSize:13,padding:0,fontFamily:"inherit"}}>{b.label}</button>
            : <span style={{fontSize:13,fontWeight:i===breadcrumb.length-1?600:400,color:i===breadcrumb.length-1?T.text:T.textMuted}}>{b.label}</span>}
        </React.Fragment>
      ))}
    </div>
    {/* Right: page actions + global controls */}
    <div style={{display:"flex",gap:6,alignItems:"center"}}>
      {actions&&<div style={{display:"flex",gap:6,alignItems:"center",marginRight:8,paddingRight:8,borderRight:`1px solid ${T.border}`}}>{actions}</div>}
      {/* Theme toggle */}
      <button onClick={()=>toggleTheme()} title={isDark?"Switch to light":"Switch to dark"}
        style={{width:32,height:32,borderRadius:8,background:"transparent",border:`1px solid ${T.border}`,color:T.textSub,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",transition:"all .15s"}}
        onMouseEnter={e=>{e.currentTarget.style.background=T.bgHover;e.currentTarget.style.color=T.text;}}
        onMouseLeave={e=>{e.currentTarget.style.background="transparent";e.currentTarget.style.color=T.textSub;}}>
        {isDark
          ? <svg width="14" height="14" viewBox="0 0 20 20" fill="currentColor"><path d="M10 2a1 1 0 011 1v1a1 1 0 11-2 0V3a1 1 0 011-1zm4 8a4 4 0 11-8 0 4 4 0 018 0zm-.464 4.95l.707.707a1 1 0 001.414-1.414l-.707-.707a1 1 0 00-1.414 1.414zm2.12-10.607a1 1 0 010 1.414l-.706.707a1 1 0 11-1.414-1.414l.707-.707a1 1 0 011.414 0zM17 11a1 1 0 100-2h-1a1 1 0 100 2h1zm-7 4a1 1 0 011 1v1a1 1 0 11-2 0v-1a1 1 0 011-1zM5.05 6.464A1 1 0 106.465 5.05l-.708-.707a1 1 0 00-1.414 1.414l.707.707zm1.414 8.486l-.707.707a1 1 0 01-1.414-1.414l.707-.707a1 1 0 011.414 1.414zM4 11a1 1 0 100-2H3a1 1 0 000 2h1z"/></svg>
          : <svg width="14" height="14" viewBox="0 0 20 20" fill="currentColor"><path d="M17.293 13.293A8 8 0 016.707 2.707a8.001 8.001 0 1010.586 10.586z"/></svg>}
      </button>
      {/* DocBot */}
      <DocBot/>
      {/* Notifications */}
      <NotifBtn/>
      {/* User menu */}
      <UserMenu/>
    </div>
  </div>
  );
};

const Metric = ({label,value,sub,delta,color})=>(
  <div style={{padding:"14px 16px",background:T.bgSurface,border:`1px solid ${T.border}`,borderRadius:10}}>
    <div style={{fontSize:11,color:T.textMuted,marginBottom:4,fontWeight:500}}>{label}</div>
    <div style={{fontSize:22,fontWeight:700,color:color||T.text,fontFamily:"'Geist Mono',monospace"}}>{value}</div>
    {delta&&<div style={{fontSize:11,color:delta.startsWith("-")?T.red:T.green,marginTop:2,fontFamily:"'Geist Mono',monospace"}}>{delta}</div>}
    {sub&&<div style={{fontSize:11,color:T.textMuted,marginTop:2}}>{sub}</div>}
  </div>
);

const SH = ({title,sub,action})=>(
  <div style={{marginBottom:12,display:"flex",alignItems:"center",justifyContent:"space-between"}}>
    <div>
      <div style={{fontSize:13,fontWeight:600,color:T.text}}>{title}</div>
      {sub&&<div style={{fontSize:11,color:T.textMuted,marginTop:2}}>{sub}</div>}
    </div>
    {action&&<div>{action}</div>}
  </div>
);

// Tabs2: accepts either string[] or {key,label}[] arrays
const Tabs2 = ({tabs,active,onChange,pill})=>{
  const items = tabs.map(t=>typeof t==="string"?{key:t,label:t}:t);
  if(pill) return (
    <div style={{display:"flex",gap:4}}>
      {items.map(t=>(
        <button key={t.key} onClick={()=>onChange(t.key)} style={{padding:"4px 12px",borderRadius:99,background:active===t.key?T.accent:T.bgElevated,color:active===t.key?"#fff":T.textSub,border:`1px solid ${active===t.key?T.accent:T.border}`,fontSize:11.5,fontWeight:active===t.key?600:400,cursor:"pointer",transition:"all .12s"}}>{t.label}</button>
      ))}
    </div>
  );
  return (
    <div style={{display:"flex",borderBottom:`1px solid ${T.border}`,marginBottom:20}}>
      {items.map(t=>(
        <button key={t.key} onClick={()=>onChange(t.key)} style={{padding:"8px 16px",background:"transparent",border:"none",borderBottom:`2px solid ${active===t.key?T.accent:"transparent"}`,color:active===t.key?T.text:T.textMuted,fontSize:13,fontWeight:active===t.key?600:400,cursor:"pointer",transition:"all .12s",marginBottom:-1,whiteSpace:"nowrap"}}>{t.label}</button>
      ))}
    </div>
  );
};


