const NotificationsPanel = ({onClose}) => {
  const onNav = useNav();
  const tagCtx = useTagCtx();
  const [notifs, setNotifs] = useState(NOTIFS.map(n=>({...n})));
  const [filter, setFilter] = useState("all");
  const unreadCount = notifs.filter(n=>n.unread).length;
  const markAll = () => setNotifs(n=>n.map(x=>({...x,unread:false})));
  const dismiss  = (id,e) => { e.stopPropagation(); setNotifs(n=>n.filter(x=>x.id!==id)); };
  const displayed = filter==="unread" ? notifs.filter(n=>n.unread) : notifs;

  return (
    <div className="scaleIn" style={{position:"absolute",top:"calc(100% + 8px)",right:0,width:380,background:T.bgSurface,border:`1px solid ${T.border}`,borderRadius:12,boxShadow:"0 12px 40px rgba(0,0,0,.3)",zIndex:600,overflow:"hidden",display:"flex",flexDirection:"column",maxHeight:520}}>
      {/* Header */}
      <div style={{padding:"12px 16px 0",flexShrink:0}}>
        <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:10}}>
          <div style={{display:"flex",alignItems:"center",gap:8}}>
            <span style={{fontSize:14,fontWeight:700,color:T.text}}>Notifications</span>
            {unreadCount>0&&<span style={{fontSize:10,fontWeight:700,padding:"2px 7px",borderRadius:99,background:T.accentDim,color:T.accent}}>{unreadCount}</span>}
          </div>
          <div style={{display:"flex",alignItems:"center",gap:8}}>
            <button onClick={markAll} style={{fontSize:11,color:T.textMuted,background:"none",border:"none",cursor:"pointer",padding:0}}>Mark all read</button>
            <button onClick={onClose} style={{width:22,height:22,background:"none",border:"none",cursor:"pointer",color:T.textMuted,display:"flex",alignItems:"center",justifyContent:"center",borderRadius:5}}>{Ic.x(11)}</button>
          </div>
        </div>
        {/* Filter tabs */}
        <div style={{display:"flex",gap:0,borderBottom:`1px solid ${T.border}`,marginLeft:-16,marginRight:-16,paddingLeft:16}}>
          {[{k:"all",l:"All"},{k:"unread",l:`Unread (${unreadCount})`}].map(t=>(
            <button key={t.k} onClick={()=>setFilter(t.k)} style={{padding:"6px 14px",background:"none",border:"none",borderBottom:`2px solid ${filter===t.k?T.accent:"transparent"}`,color:filter===t.k?T.text:T.textMuted,fontSize:12,fontWeight:filter===t.k?600:400,cursor:"pointer",marginBottom:-1,transition:"all .12s"}}>{t.l}</button>
          ))}
        </div>
      </div>
      {/* Tag governance section */}
      {tagCtx&&(()=>{
        const unresolved = tagCtx.unresolvedCount;
        const conflicts  = tagCtx.conflictCount;
        const pending    = tagCtx.pendingCount;
        const allClear   = unresolved===0;
        return (
          <div style={{padding:"10px 16px",borderBottom:`1px solid ${T.border}`,background:allClear?"transparent":`${T.amber}08`}}>
            <div style={{display:"flex",alignItems:"center",gap:7,marginBottom:allClear?0:6}}>
              {Ic.tag(12)}
              <span style={{fontSize:11.5,fontWeight:700,color:T.text}}>Tag Governance</span>
              {allClear
                ? <span style={{fontSize:10.5,color:"#16a34a",marginLeft:"auto",fontWeight:600}}>✓ All clear</span>
                : <span style={{fontSize:10,fontWeight:700,padding:"1px 6px",borderRadius:99,background:"rgba(251,191,36,.15)",color:T.amber,border:"1px solid rgba(251,191,36,.25)",marginLeft:"auto"}}>{unresolved}</span>}
            </div>
            {!allClear&&<div style={{display:"flex",gap:10}}>
              {unresolved>0&&<div style={{display:"flex",alignItems:"center",gap:4,fontSize:11}}>
                <span style={{width:6,height:6,borderRadius:"50%",background:T.amber,display:"block"}}/>
                <span style={{color:T.textSub}}>{unresolved} unresolved</span>
              </div>}
              {conflicts>0&&<div style={{display:"flex",alignItems:"center",gap:4,fontSize:11}}>
                <span style={{width:6,height:6,borderRadius:"50%",background:T.rose,display:"block"}}/>
                <span style={{color:T.textSub}}>{conflicts} conflicts</span>
              </div>}
              {pending>0&&<div style={{display:"flex",alignItems:"center",gap:4,fontSize:11}}>
                <span style={{width:6,height:6,borderRadius:"50%",background:T.violet,display:"block"}}/>
                <span style={{color:T.textSub}}>{pending} pending</span>
              </div>}
              <button onClick={()=>{onNav("stewardship");onClose();}} style={{fontSize:10.5,color:T.accent,background:"none",border:"none",cursor:"pointer",marginLeft:"auto",fontWeight:500,padding:0}}>View →</button>
            </div>}
          </div>
        );
      })()}
      {/* List */}
      <div style={{flex:1,overflowY:"auto"}}>
        {displayed.length===0&&<div style={{padding:"32px 16px",textAlign:"center",color:T.textMuted,fontSize:12}}>No notifications</div>}
        {displayed.map(n=>{
          const cfg = NOTIF_TYPE_CFG[n.type]||NOTIF_TYPE_CFG.alert;
          return (
            <div key={n.id} style={{padding:"11px 16px",borderBottom:`1px solid ${T.border}`,background:n.unread?T.bgElevated:"transparent",transition:"background .1s"}}
              onMouseEnter={e=>e.currentTarget.style.background=T.bgHover}
              onMouseLeave={e=>e.currentTarget.style.background=n.unread?T.bgElevated:"transparent"}>
              <div style={{display:"flex",alignItems:"flex-start",gap:10}}>
                {/* Unread dot */}
                <div style={{width:6,flexShrink:0,display:"flex",justifyContent:"center",paddingTop:5}}>
                  {n.unread&&<span style={{width:6,height:6,borderRadius:"50%",background:T.accent,display:"block"}}/>}
                </div>
                {/* Type icon */}
                <div style={{width:28,height:28,borderRadius:7,background:cfg.bg,display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0,color:cfg.color}}>{cfg.icon}</div>
                {/* Content */}
                <div style={{flex:1,minWidth:0}}>
                  <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",gap:8,marginBottom:2}}>
                    <span style={{fontSize:12.5,fontWeight:n.unread?600:500,color:T.text}}>{n.title}</span>
                    <span style={{fontSize:10.5,color:T.textMuted,flexShrink:0}}>{n.time}</span>
                  </div>
                  <div style={{fontSize:11.5,color:T.textMuted,lineHeight:1.45}}>{n.body}</div>
                </div>
                {/* Actions */}
                <div style={{display:"flex",alignItems:"center",gap:4,flexShrink:0}}>
                  <button onClick={e=>dismiss(n.id,e)} title="Dismiss" style={{width:22,height:22,background:"none",border:"none",cursor:"pointer",color:T.textMuted,display:"flex",alignItems:"center",justifyContent:"center",borderRadius:5,opacity:.6}}
                    onMouseEnter={e=>e.currentTarget.style.opacity="1"} onMouseLeave={e=>e.currentTarget.style.opacity=".6"}>{Ic.x(10)}</button>
                  <button onClick={()=>{onNav(n.nav);onClose();}} title="Go to" style={{width:22,height:22,background:"none",border:"none",cursor:"pointer",color:T.textMuted,display:"flex",alignItems:"center",justifyContent:"center",borderRadius:5,opacity:.6}}
                    onMouseEnter={e=>e.currentTarget.style.opacity="1"} onMouseLeave={e=>e.currentTarget.style.opacity=".6"}>
                    <svg width="10" height="10" viewBox="0 0 10 10" fill="none"><path d="M3 2l4 3-4 3" stroke="currentColor" strokeWidth="1.4" strokeLinecap="round"/></svg>
                  </button>
                </div>
              </div>
            </div>
          );
        })}
      </div>
      {/* Footer */}
      <div style={{padding:"10px 16px",borderTop:`1px solid ${T.border}`,textAlign:"center",flexShrink:0}}>
        <button onClick={onClose} style={{fontSize:12,color:T.accent,background:"none",border:"none",cursor:"pointer",fontWeight:500}}>View all notifications</button>
      </div>
    </div>
  );
};

const NotifBtn = () => {
  const [open, setOpen] = useState(false);
  const unread = NOTIFS.filter(n=>n.unread).length;
  const ref = useRef(null);
  useEffect(()=>{const fn=e=>{if(ref.current&&!ref.current.contains(e.target))setOpen(false);};document.addEventListener("mousedown",fn);return()=>document.removeEventListener("mousedown",fn);},[]);
  return (
    <div ref={ref} style={{position:"relative"}}>
      <button onClick={()=>setOpen(o=>!o)} style={{width:32,height:32,borderRadius:8,background:open?T.bgHover:"transparent",border:`1px solid ${open?T.borderLight:T.border}`,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",color:T.textSub,transition:"all .15s",position:"relative"}}
        onMouseEnter={e=>{if(!open){e.currentTarget.style.background=T.bgHover;e.currentTarget.style.borderColor=T.borderLight;}}}
        onMouseLeave={e=>{if(!open){e.currentTarget.style.background="transparent";e.currentTarget.style.borderColor=T.border;}}}>
        {Ic.bell(15)}
        {unread>0&&<span style={{position:"absolute",top:5,right:5,width:7,height:7,borderRadius:"50%",background:T.rose,border:`1.5px solid ${T.bg}`}}/>}
      </button>
      {open&&<NotificationsPanel onClose={()=>setOpen(false)}/>}
    </div>
  );
};

