const AssetCommentsTab = ({onToast})=>{
  const [comments,setComments]=useState(COMMENTS);
  const [newComment,setNewComment]=useState("");
  const submit=()=>{
    if(!newComment.trim())return;
    setComments([...comments,{id:comments.length+1,user:"maya.chen",avatar:"MC",text:newComment,time:"Just now",resolved:false}]);
    setNewComment("");
    onToast("Comment posted","success");
  };
  return <div className="fadeIn">
    <div style={{display:"flex",flexDirection:"column",gap:10,marginBottom:16}}>
      {comments.map(c=>(
        <Card2 key={c.id} style={{opacity:c.resolved?.7:1}}>
          <div style={{padding:14}}>
            <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:10}}>
              <div style={{width:26,height:26,borderRadius:7,background:T.bgHover,display:"flex",alignItems:"center",justifyContent:"center",fontSize:10,fontWeight:700,color:T.accent}}>{c.avatar}</div>
              <span style={{fontSize:12,fontWeight:500,color:T.text}}>{c.user}</span>
              <span style={{fontSize:11,color:T.textMuted}}>{c.time}</span>
              {c.resolved&&<Badge color={T.green} bg={T.accentDim} style={{marginLeft:"auto"}}>Resolved</Badge>}
              <div style={{marginLeft:"auto",display:"flex",gap:6}}>
                {!c.resolved&&<button onClick={()=>setComments(comments.map(cc=>cc.id===c.id?{...cc,resolved:true}:cc))} style={{background:"transparent",border:"none",color:T.textMuted,cursor:"pointer",fontSize:11,display:"flex",alignItems:"center",gap:4}}>{Ic.check(12)} Resolve</button>}
              </div>
            </div>
            <p style={{fontSize:13,color:T.textSub,lineHeight:1.7}}>{c.text}</p>
          </div>
        </Card2>
      ))}
    </div>
    <Card2>
      <div style={{padding:14}}>
        <div style={{fontSize:12,color:T.textSub,marginBottom:8}}>Add a comment</div>
        <Input2 multiline rows={3} placeholder="Leave a comment, ask a question, or flag an issue…" value={newComment} onChange={e=>setNewComment(e.target.value)}/>
        <div style={{display:"flex",justifyContent:"flex-end",marginTop:10}}>
          <Btn variant="primary" icon={Ic.comment(12)} onClick={submit}>Post Comment</Btn>
        </div>
      </div>
    </Card2>
  </div>;
};

// ─────────────────────────────────────────────
// ASSET DETAIL
// ─────────────────────────────────────────────
const AssetDetail = ({asset, onBack, onToast}) => {
  const [tab,        setTab]       = useState("overview");
  const [data,         setData]        = useState({...asset,owners:asset.owners||[asset.owner],stewards:asset.stewards||(asset.steward?[asset.steward]:[]),tags:[...(asset.tags||[])]});
  const [certOpen,     setCertOpen]    = useState(false);
  const [domainOpen,   setDomainOpen]  = useState(false);
  const [ownerOpen,    setOwnerOpen]   = useState(false);
  const [ownerSearch,  setOwnerSearch] = useState("");
  const [stewardOpen,  setStewardOpen] = useState(false);
  const [stewardSearch,setStewardSearch]=useState("");
  const [tagInput,     setTagInput]    = useState("");
  const [certModal,  setCertModal] = useState(false);
  const [certNote,   setCertNote]  = useState("");

  const DOMAINS_LIST = ["Commerce","Finance","Product","Marketing","ML","Engineering"];
  const USERS_LIST   = ["maya.chen","sarah.kim","alex.wu","dev.patel","lisa.ray","priya.nair","james.oh"];
  const ava          = name => (name||"?").split(".").map(s=>s[0]?.toUpperCase()||"").join("");

  // cert meta inline
  const CMETA = {
    "Draft":       {color:"#6b7280",bg:"rgba(107,114,128,.1)", border:"rgba(107,114,128,.25)",icon:"◐"},
    "In Review":   {color:"#d97706",bg:"rgba(217,119,6,.12)",  border:"rgba(217,119,6,.3)",   icon:"⏳"},
    "Approved":    {color:"#16a34a",bg:"rgba(22,163,74,.12)",  border:"rgba(22,163,74,.3)",   icon:"✓"},
    "Rejected":    {color:"#e11d48",bg:"rgba(225,29,72,.12)",  border:"rgba(225,29,72,.3)",   icon:"✕"},
    "Deprecated":  {color:"#7c3aed",bg:"rgba(124,58,237,.1)",  border:"rgba(124,58,237,.25)", icon:"—"},
  };

  const cm = CMETA[data.cert]||CMETA["Draft"];
  const owners   = Array.isArray(data.owners)  ? data.owners   : (data.owner   ? [data.owner]   : []);
  const stewards = Array.isArray(data.stewards) ? data.stewards : (data.steward ? [data.steward] : []);

  // close all dropdowns on outside click
  useEffect(()=>{
    if(!certOpen&&!domainOpen&&!ownerOpen&&!stewardOpen) return;
    const close=()=>{setCertOpen(false);setDomainOpen(false);setOwnerOpen(false);setOwnerSearch("");setStewardOpen(false);setStewardSearch("");};
    document.addEventListener("mousedown",close);
    return ()=>document.removeEventListener("mousedown",close);
  },[certOpen,domainOpen,ownerOpen,stewardOpen]);

  const addTag=()=>{
    const t=tagInput.trim().toLowerCase();
    if(!t||data.tags.includes(t))return;
    setData(d=>({...d,tags:[...d.tags,t]}));
    setTagInput("");
  };

  const tabs=[
    {key:"overview",label:"Overview"},{key:"schema",label:"Schema"},
    {key:"lineage",label:"Lineage"},{key:"quality",label:"Quality"},
    {key:"policies",label:"Policies"},{key:"access",label:"Access"},
    {key:"usage",label:"Usage"},{key:"activity",label:"Activity"},
    {key:"comments",label:`Comments (${COMMENTS.length})`},
  ];

  const handleCertify=()=>{
    setData(d=>({...d,cert:"Approved"}));
    setCertModal(false);
    onToast(`${asset.name} certified successfully`,"success");
  };

  // helper label for sidebar sections
  const MetaLabel = ({children})=>(
    <div style={{fontSize:10.5,fontWeight:700,color:T.textMuted,textTransform:"uppercase",letterSpacing:"0.08em",marginBottom:8}}>
      {children}
    </div>
  );

  return <div className="fadeUp" style={{height:"100%",display:"flex",flexDirection:"column"}}>
    <Topbar breadcrumb={[{label:"Data Catalog",onClick:onBack},{label:asset.name}]}/>

    {/* ── Asset header ── */}
    <div style={{background:T.bgSurface,borderBottom:`1px solid ${T.border}`,flexShrink:0,padding:"16px 28px 0"}}>
      {/* type + db path */}
      <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:8}}>
        <TypeBadge type={data.type}/>
        <span style={{fontSize:11.5,color:T.textMuted,fontFamily:"'Geist Mono',monospace"}}>{data.db}</span>
      </div>
      {/* name + actions */}
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",gap:12,marginBottom:14}}>
        <h2 style={{fontSize:22,fontWeight:700,fontFamily:"'Geist Mono',monospace",color:T.text,letterSpacing:"-0.04em",margin:0}}>{data.name}</h2>
        <div style={{display:"flex",gap:7,alignItems:"center",flexShrink:0}}>
          {data.cert!=="Approved"&&(
            <button onClick={()=>setCertModal(true)}
              style={{display:"inline-flex",alignItems:"center",gap:6,padding:"6px 14px",borderRadius:8,background:"#16a34a12",border:"1px solid rgba(22,163,74,.3)",color:"#16a34a",fontSize:12.5,fontWeight:600,cursor:"pointer",transition:"opacity .1s"}}
              onMouseEnter={e=>e.currentTarget.style.opacity=".8"} onMouseLeave={e=>e.currentTarget.style.opacity="1"}>
              {Ic.cert(12)} Certify
            </button>
          )}
          <button onClick={()=>onToast("Edit panel coming soon","success")}
            style={{display:"inline-flex",alignItems:"center",gap:6,padding:"6px 14px",borderRadius:8,background:T.bgElevated,border:`1px solid ${T.border}`,color:T.textSub,fontSize:12.5,fontWeight:500,cursor:"pointer",transition:"all .1s"}}
            onMouseEnter={e=>{e.currentTarget.style.borderColor=T.accent;e.currentTarget.style.color=T.accent;}}
            onMouseLeave={e=>{e.currentTarget.style.borderColor=T.border;e.currentTarget.style.color=T.textSub;}}>
            {Ic.edit(11)} Edit
          </button>
        </div>
      </div>
      {/* tab bar */}
      <div style={{display:"flex",marginBottom:-1}}>
        {tabs.map(t=>(
          <button key={t.key} onClick={()=>setTab(t.key)}
            style={{padding:"9px 16px",background:"transparent",border:"none",borderBottom:`2px solid ${tab===t.key?T.accent:"transparent"}`,color:tab===t.key?T.text:T.textMuted,fontSize:13,fontWeight:tab===t.key?600:400,cursor:"pointer",transition:"all .12s",whiteSpace:"nowrap"}}>
            {t.label}
          </button>
        ))}
      </div>
    </div>

    {/* ── Body: content + right sidebar ── */}
    <div style={{flex:1,display:"flex",overflow:"hidden"}}>

      {/* Main content */}
      <div style={{flex:1,overflowY:"auto",padding:24,minWidth:0}}>
        {tab==="overview"  && <AssetOverview asset={asset} data={data} setData={setData} onToast={onToast}/>}
        {tab==="schema"    && <AssetSchema asset={asset} onToast={onToast}/>}
        {tab==="lineage"   && <AssetLineageFull asset={asset}/>}
        {tab==="quality"   && <AssetQualityTab asset={data}/>}
{tab==="policies"  && <AssetPoliciesTab/>}
        {tab==="access"    && <AssetAccessTab onToast={onToast}/>}
        {tab==="usage"     && <AssetUsageTab/>}
        {tab==="activity"  && <AssetActivityTab/>}
        {tab==="comments"  && <AssetCommentsTab onToast={onToast}/>}
      </div>

      {/* ── Right metadata sidebar ── */}
      <div style={{width:260,flexShrink:0,borderLeft:`1px solid ${T.border}`,background:T.bgSurface,overflowY:"auto"}}>

        {/* DETAILS */}
        <div style={{padding:"16px",borderBottom:`1px solid ${T.border}`}}>
          <MetaLabel>Details</MetaLabel>
          {[
            {l:"Quality",   v:<QScore score={data.quality}/>},
            {l:"Row Count", v:<span style={{fontSize:12,fontFamily:"'Geist Mono',monospace",color:T.text}}>{data.rows}</span>},
            {l:"Size",      v:<span style={{fontSize:12,fontFamily:"'Geist Mono',monospace",color:T.text}}>{data.size}</span>},
            {l:"Freshness", v:<span style={{fontSize:12,color:T.textSub}}>{data.slaFreshness}</span>},
            {l:"Updated",   v:<span style={{fontSize:12,color:T.textMuted}}>{data.updated}</span>},
          ].map(m=>(
            <div key={m.l} style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:8,fontSize:12}}>
              <span style={{color:T.textMuted}}>{m.l}</span>
              {m.v}
            </div>
          ))}
        </div>

        {/* CERTIFICATE */}
        <div style={{padding:"16px",borderBottom:`1px solid ${T.border}`,position:"relative"}}>
          <MetaLabel>Certificate</MetaLabel>
          <button onMouseDown={e=>{e.stopPropagation();setCertOpen(p=>!p);setDomainOpen(false);setOwnerOpen(false);}}
            style={{width:"100%",display:"flex",alignItems:"center",justifyContent:"space-between",padding:"7px 11px",borderRadius:8,background:cm.bg,border:`1px solid ${cm.border}`,cursor:"pointer",transition:"opacity .1s"}}
            onMouseEnter={e=>e.currentTarget.style.opacity=".85"} onMouseLeave={e=>e.currentTarget.style.opacity="1"}>
            <span style={{display:"flex",alignItems:"center",gap:7,fontSize:13,fontWeight:700,color:cm.color}}>
              <span style={{fontSize:15}}>{cm.icon}</span>{data.cert}
            </span>
            <svg width="10" height="10" viewBox="0 0 10 10" fill="none" style={{color:cm.color,flexShrink:0}}><path d="M2 3.5l3 3 3-3" stroke="currentColor" strokeWidth="1.4" strokeLinecap="round"/></svg>
          </button>
          {certOpen&&(
            <div onMouseDown={e=>e.stopPropagation()} style={{position:"absolute",top:"calc(100% - 4px)",left:16,right:16,zIndex:300,background:T.bgSurface,border:`1px solid ${T.border}`,borderRadius:10,boxShadow:"0 8px 24px rgba(0,0,0,.18)",overflow:"hidden"}}>
              {Object.entries(CMETA).map(([c,m])=>(
                <button key={c} onMouseDown={e=>{e.stopPropagation();setData(d=>({...d,cert:c}));setCertOpen(false);onToast(`Certification set to ${c}`,"success");}}
                  style={{width:"100%",display:"flex",alignItems:"center",gap:8,padding:"9px 14px",background:data.cert===c?m.bg:"transparent",border:"none",cursor:"pointer",textAlign:"left",transition:"background .1s"}}
                  onMouseEnter={e=>{if(data.cert!==c)e.currentTarget.style.background=T.bgHover;}} onMouseLeave={e=>{if(data.cert!==c)e.currentTarget.style.background="transparent";}}>
                  <span style={{fontSize:15}}>{m.icon}</span>
                  <span style={{flex:1,fontSize:12.5,fontWeight:600,color:m.color}}>{c}</span>
                  {data.cert===c&&<span style={{fontSize:12,color:m.color}}>✓</span>}
                </button>
              ))}
            </div>
          )}
        </div>

        {/* DOMAIN */}
        <div style={{padding:"16px",borderBottom:`1px solid ${T.border}`,position:"relative"}}>
          <MetaLabel>Domain</MetaLabel>
          <button onMouseDown={e=>{e.stopPropagation();setDomainOpen(p=>!p);setCertOpen(false);setOwnerOpen(false);}}
            style={{width:"100%",display:"flex",alignItems:"center",justifyContent:"space-between",padding:"7px 11px",borderRadius:8,background:T.accentDim,border:`1px solid ${T.accent}33`,cursor:"pointer",fontSize:13,fontWeight:600,color:T.accent,transition:"opacity .1s"}}
            onMouseEnter={e=>e.currentTarget.style.opacity=".8"} onMouseLeave={e=>e.currentTarget.style.opacity="1"}>
            {data.domain}
            <svg width="10" height="10" viewBox="0 0 10 10" fill="none" style={{flexShrink:0,color:T.accent}}><path d="M2 3.5l3 3 3-3" stroke="currentColor" strokeWidth="1.4" strokeLinecap="round"/></svg>
          </button>
          {domainOpen&&(
            <div onMouseDown={e=>e.stopPropagation()} style={{position:"absolute",top:"calc(100% - 4px)",left:16,right:16,zIndex:300,background:T.bgSurface,border:`1px solid ${T.border}`,borderRadius:10,boxShadow:"0 8px 24px rgba(0,0,0,.18)",overflow:"hidden"}}>
              {DOMAINS_LIST.map(d=>(
                <button key={d} onMouseDown={e=>{e.stopPropagation();setData(dd=>({...dd,domain:d}));setDomainOpen(false);onToast(`Domain set to ${d}`,"success");}}
                  style={{width:"100%",display:"flex",alignItems:"center",justifyContent:"space-between",padding:"8px 14px",background:data.domain===d?T.accentDim:"transparent",border:"none",cursor:"pointer",fontSize:12.5,color:data.domain===d?T.accent:T.textSub,fontWeight:data.domain===d?600:400,transition:"background .1s"}}
                  onMouseEnter={e=>{if(data.domain!==d)e.currentTarget.style.background=T.bgHover;}} onMouseLeave={e=>{if(data.domain!==d)e.currentTarget.style.background="transparent";}}>
                  {d}{data.domain===d&&<span style={{color:T.accent,fontSize:12}}>✓</span>}
                </button>
              ))}
            </div>
          )}
        </div>

        {/* OWNERS */}
        <div style={{padding:"16px",borderBottom:`1px solid ${T.border}`,position:"relative"}}>
          <MetaLabel>Owners</MetaLabel>
          <div style={{display:"flex",flexWrap:"wrap",gap:5,marginBottom:8}}>
            {owners.map((o,i)=>(
              <div key={i} style={{display:"inline-flex",alignItems:"center",gap:5,padding:"3px 8px 3px 5px",borderRadius:99,background:T.bgElevated,border:`1px solid ${T.border}`,transition:"border-color .1s"}}
                onMouseEnter={e=>e.currentTarget.style.borderColor=T.borderLight} onMouseLeave={e=>e.currentTarget.style.borderColor=T.border}>
                <div style={{width:20,height:20,borderRadius:"50%",background:T.accentDim,border:`1px solid ${T.accent}33`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:7.5,fontWeight:700,color:T.accent,flexShrink:0}}>{ava(o)}</div>
                <span style={{fontSize:12,color:T.text,fontWeight:500}}>{o}</span>
                <button onClick={()=>{const no=owners.filter((_,j)=>j!==i);setData(d=>({...d,owners:no,owner:no[0]||""}));}}
                  style={{background:"none",border:"none",cursor:"pointer",color:T.textMuted,padding:0,display:"flex",lineHeight:1}}
                  onMouseEnter={e=>e.currentTarget.style.color=T.rose} onMouseLeave={e=>e.currentTarget.style.color=T.textMuted}>
                  <svg width="8" height="8" viewBox="0 0 10 10" fill="none"><path d="M1.5 1.5l7 7M8.5 1.5l-7 7" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round"/></svg>
                </button>
              </div>
            ))}
          </div>
          <button onMouseDown={e=>{e.stopPropagation();setOwnerOpen(p=>{if(!p)setOwnerSearch("");return !p;});setCertOpen(false);setDomainOpen(false);}}
            style={{display:"inline-flex",alignItems:"center",gap:5,fontSize:11.5,padding:"4px 10px",borderRadius:6,border:`1px dashed ${ownerOpen?T.accent:T.border}`,background:"none",color:ownerOpen?T.accent:T.textMuted,cursor:"pointer",transition:"all .12s"}}
            onMouseEnter={e=>{if(!ownerOpen){e.currentTarget.style.borderColor=T.accent;e.currentTarget.style.color=T.accent;}}}
            onMouseLeave={e=>{if(!ownerOpen){e.currentTarget.style.borderColor=T.border;e.currentTarget.style.color=T.textMuted;}}}>
            <svg width="9" height="9" viewBox="0 0 10 10" fill="none"><path d="M5 1v8M1 5h8" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round"/></svg> Add owner
          </button>
          {ownerOpen&&(
            <div onMouseDown={e=>e.stopPropagation()} style={{position:"absolute",left:16,right:16,top:"calc(100% - 4px)",zIndex:300,background:T.bgSurface,border:`1px solid ${T.border}`,borderRadius:10,boxShadow:"0 8px 24px rgba(0,0,0,.18)",overflow:"hidden"}}>
              <div style={{padding:"8px 10px",borderBottom:`1px solid ${T.border}`}}>
                <input autoFocus value={ownerSearch} onChange={e=>setOwnerSearch(e.target.value)} placeholder="Search users…"
                  style={{width:"100%",padding:"5px 9px",background:T.bgElevated,border:`1px solid ${T.border}`,borderRadius:6,color:T.text,fontSize:12,outline:"none"}}
                  onFocus={e=>e.target.style.borderColor=T.accent} onBlur={e=>e.target.style.borderColor=T.border}/>
              </div>
              <div style={{maxHeight:170,overflowY:"auto"}}>
                {USERS_LIST.filter(u=>!ownerSearch||u.toLowerCase().includes(ownerSearch.toLowerCase())).map(u=>{
                  const sel=owners.includes(u);
                  return <button key={u} onMouseDown={e=>{e.stopPropagation();
                    if(sel){const no=owners.filter(x=>x!==u);setData(d=>({...d,owners:no,owner:no[0]||""}));}
                    else setData(d=>({...d,owners:[...owners,u],owner:owners[0]||u}));}}
                    style={{width:"100%",display:"flex",alignItems:"center",gap:9,padding:"8px 12px",background:sel?T.bgElevated:"transparent",border:"none",cursor:"pointer",textAlign:"left",transition:"background .1s"}}
                    onMouseEnter={e=>{if(!sel)e.currentTarget.style.background=T.bgHover;}} onMouseLeave={e=>{if(!sel)e.currentTarget.style.background="transparent";}}>
                    <div style={{width:22,height:22,borderRadius:6,background:T.accentDim,display:"flex",alignItems:"center",justifyContent:"center",fontSize:8,fontWeight:700,color:T.accent,flexShrink:0}}>{ava(u)}</div>
                    <span style={{flex:1,fontSize:12,color:T.text}}>{u}</span>
                    {sel&&<span style={{fontSize:12,color:T.accent,fontWeight:700}}>✓</span>}
                  </button>;
                })}
              </div>
            </div>
          )}
        </div>

        {/* STEWARDS — multi-select */}
        {(()=>{
          return (
          <div style={{padding:"16px",borderBottom:`1px solid ${T.border}`,position:"relative"}}>
            <MetaLabel>Stewards</MetaLabel>
            <div style={{display:"flex",flexWrap:"wrap",gap:5,marginBottom:stewards.length?8:0}}>
              {stewards.map((s,i)=>(
                <div key={i} style={{display:"inline-flex",alignItems:"center",gap:5,padding:"3px 8px 3px 5px",borderRadius:99,background:T.bgElevated,border:`1px solid ${T.border}`,transition:"border-color .1s"}}
                  onMouseEnter={e=>e.currentTarget.style.borderColor=T.borderLight} onMouseLeave={e=>e.currentTarget.style.borderColor=T.border}>
                  <div style={{width:20,height:20,borderRadius:"50%",background:"rgba(217,119,6,.12)",border:"1px solid rgba(217,119,6,.25)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:7.5,fontWeight:700,color:"#d97706",flexShrink:0}}>{ava(s)}</div>
                  <span style={{fontSize:12,color:T.text,fontWeight:500}}>{s}</span>
                  <button onClick={()=>{const ns=stewards.filter((_,j)=>j!==i);setData(d=>({...d,stewards:ns,steward:ns[0]||""}));}}
                    style={{background:"none",border:"none",cursor:"pointer",color:T.textMuted,padding:0,display:"flex",lineHeight:1}}
                    onMouseEnter={e=>e.currentTarget.style.color=T.rose} onMouseLeave={e=>e.currentTarget.style.color=T.textMuted}>
                    <svg width="8" height="8" viewBox="0 0 10 10" fill="none"><path d="M1.5 1.5l7 7M8.5 1.5l-7 7" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round"/></svg>
                  </button>
                </div>
              ))}
            </div>
            <button onMouseDown={e=>{e.stopPropagation();setStewardOpen(p=>!p);setCertOpen(false);setDomainOpen(false);setOwnerOpen(false);}}
              style={{display:"inline-flex",alignItems:"center",gap:5,fontSize:11.5,color:stewardOpen?"#d97706":T.textMuted,background:"none",border:`1px dashed ${stewardOpen?"#d97706":T.border}`,borderRadius:6,padding:"4px 10px",cursor:"pointer",transition:"all .12s"}}
              onMouseEnter={e=>{if(!stewardOpen){e.currentTarget.style.borderColor="#d97706";e.currentTarget.style.color="#d97706";}}}
              onMouseLeave={e=>{if(!stewardOpen){e.currentTarget.style.borderColor=T.border;e.currentTarget.style.color=T.textMuted;}}}>
              <svg width="9" height="9" viewBox="0 0 10 10" fill="none"><path d="M5 1v8M1 5h8" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round"/></svg>
              Add steward
            </button>
            {stewardOpen&&(
              <div onMouseDown={e=>e.stopPropagation()} style={{position:"absolute",left:16,right:16,top:"calc(100% - 4px)",zIndex:300,background:T.bgSurface,border:`1px solid ${T.border}`,borderRadius:10,boxShadow:"0 8px 24px rgba(0,0,0,.18)",overflow:"hidden"}}>
                <div style={{padding:"8px 10px",borderBottom:`1px solid ${T.border}`}}>
                  <input autoFocus placeholder="Search users…" value={stewardSearch} onChange={e=>setStewardSearch(e.target.value)}
                    style={{width:"100%",padding:"5px 9px",background:T.bgElevated,border:`1px solid ${T.border}`,borderRadius:6,color:T.text,fontSize:12,outline:"none",boxSizing:"border-box"}}
                    onFocus={e=>e.target.style.borderColor="#d97706"} onBlur={e=>e.target.style.borderColor=T.border}/>
                </div>
                <div style={{maxHeight:170,overflowY:"auto"}}>
                  {USERS_LIST.filter(u=>!stewardSearch||u.toLowerCase().includes(stewardSearch.toLowerCase())).map(u=>{
                    const sel=stewards.includes(u);
                    return <button key={u} onMouseDown={e=>{e.stopPropagation();
                      if(sel){const ns=stewards.filter(x=>x!==u);setData(d=>({...d,stewards:ns,steward:ns[0]||""}));}
                      else setData(d=>({...d,stewards:[...stewards,u],steward:stewards[0]||u}));}}
                      style={{width:"100%",display:"flex",alignItems:"center",gap:9,padding:"8px 12px",background:sel?"rgba(217,119,6,.08)":"transparent",border:"none",cursor:"pointer",textAlign:"left",transition:"background .1s"}}
                      onMouseEnter={e=>{if(!sel)e.currentTarget.style.background=T.bgHover;}} onMouseLeave={e=>{if(!sel)e.currentTarget.style.background="transparent";}}>
                      <div style={{width:22,height:22,borderRadius:"50%",background:"rgba(217,119,6,.15)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:8,fontWeight:700,color:"#d97706",flexShrink:0}}>{ava(u)}</div>
                      <span style={{flex:1,fontSize:12,color:T.text}}>{u}</span>
                      {sel&&<span style={{fontSize:12,color:"#d97706",fontWeight:700}}>✓</span>}
                    </button>;
                  })}
                </div>
              </div>
            )}
          </div>
          );
        })()}

        {/* TAGS */}
        {(()=>{
          const TAG_C = {
            PII:       {bg:"rgba(225,29,72,.1)",  color:"#e11d48",border:"rgba(225,29,72,.25)"},
            revenue:   {bg:"rgba(37,99,235,.08)", color:"#2563eb",border:"rgba(37,99,235,.2)"},
            finance:   {bg:"rgba(37,99,235,.08)", color:"#2563eb",border:"rgba(37,99,235,.2)"},
            KPI:       {bg:"rgba(22,163,74,.08)", color:"#16a34a",border:"rgba(22,163,74,.2)"},
            sensitive: {bg:"rgba(124,58,237,.08)",color:"#7c3aed",border:"rgba(124,58,237,.2)"},
            events:    {bg:"rgba(6,182,212,.08)", color:"#0891b2",border:"rgba(6,182,212,.2)"},
            model:     {bg:"rgba(99,102,241,.08)",color:"#6366f1",border:"rgba(99,102,241,.2)"},
            etl:       {bg:"rgba(245,158,11,.08)",color:"#d97706",border:"rgba(245,158,11,.2)"},
          };
          const tc = tag => TAG_C[tag]||{bg:T.bgElevated,color:T.textSub,border:T.border};
          return (
        <div style={{padding:"16px",borderBottom:`1px solid ${T.border}`,position:"relative"}}>
          <MetaLabel>Tags</MetaLabel>
          <div style={{display:"flex",flexWrap:"wrap",gap:5,marginBottom:8}}>
            {(data.tags||[]).map(t=>{const c=tc(t);return(
              <span key={t} style={{display:"inline-flex",alignItems:"center",gap:4,fontSize:11.5,padding:"3px 10px",borderRadius:6,background:c.bg,color:c.color,border:`1px solid ${c.border}`,fontWeight:500}}>
                {t}
                <button onClick={()=>setData(d=>({...d,tags:d.tags.filter(x=>x!==t)}))} style={{background:"none",border:"none",cursor:"pointer",color:"inherit",padding:0,display:"flex",opacity:.6,lineHeight:1}}
                  onMouseEnter={e=>e.currentTarget.style.opacity="1"} onMouseLeave={e=>e.currentTarget.style.opacity=".6"}>
                  <svg width="8" height="8" viewBox="0 0 10 10" fill="none"><path d="M1.5 1.5l7 7M8.5 1.5l-7 7" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round"/></svg>
                </button>
              </span>
            );})}
          </div>
          <button onMouseDown={e=>{e.stopPropagation();setTagInput(p=>p==="_open_"?"":("_open_"));setCertOpen(false);setDomainOpen(false);setOwnerOpen(false);}}
            style={{display:"inline-flex",alignItems:"center",gap:5,fontSize:11.5,padding:"4px 10px",borderRadius:6,border:`1px dashed ${tagInput==="_open_"?T.accent:T.border}`,background:"none",color:tagInput==="_open_"?T.accent:T.textMuted,cursor:"pointer",transition:"all .12s"}}
            onMouseEnter={e=>{if(tagInput!=="open_"){e.currentTarget.style.borderColor=T.accent;e.currentTarget.style.color=T.accent;}}}
            onMouseLeave={e=>{if(tagInput!=="open_"){e.currentTarget.style.borderColor=T.border;e.currentTarget.style.color=T.textMuted;}}}>
            <svg width="9" height="9" viewBox="0 0 10 10" fill="none"><path d="M5 1v8M1 5h8" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round"/></svg> Add tag
          </button>
          {tagInput==="_open_"&&(
            <div onMouseDown={e=>e.stopPropagation()} style={{position:"absolute",left:16,top:"calc(100% + 4px)",zIndex:300,background:T.bgSurface,border:`1px solid ${T.border}`,borderRadius:10,boxShadow:"0 8px 24px rgba(0,0,0,.18)",padding:"10px 12px",minWidth:220}}>
              <div style={{fontSize:11,color:T.textMuted,marginBottom:8,fontWeight:600,textTransform:"uppercase",letterSpacing:"0.06em"}}>Suggested</div>
              <div style={{display:"flex",flexWrap:"wrap",gap:5}}>
                {["PII","revenue","finance","KPI","events","sensitive","dimension","model","etl","marketing"].filter(s=>!data.tags.includes(s)).map(s=>(
                  <button key={s} onMouseDown={e=>{e.stopPropagation();if(!data.tags.includes(s)){setData(d=>({...d,tags:[...d.tags,s]}));}setTagInput("");}}
                    style={{padding:"4px 10px",borderRadius:6,background:T.bgElevated,border:`1px solid ${T.border}`,color:T.textSub,fontSize:12,cursor:"pointer",transition:"all .1s"}}
                    onMouseEnter={e=>{e.currentTarget.style.background=T.accentDim;e.currentTarget.style.color=T.accent;e.currentTarget.style.borderColor=T.accent+"55";}}
                    onMouseLeave={e=>{e.currentTarget.style.background=T.bgElevated;e.currentTarget.style.color=T.textSub;e.currentTarget.style.borderColor=T.border;}}>
                    {s}
                  </button>
                ))}
              </div>
            </div>
          )}
        </div>
          );
        })()}

        {/* ACTIONS */}
        <div style={{padding:"16px"}}>
          <MetaLabel>Actions</MetaLabel>
          {[
            {l:"Request Access", fn:()=>onToast("Access request sent","success")},
            {l:"Copy Link",      fn:()=>onToast("Link copied","success")},
            {l:"View Lineage",   fn:()=>setTab("lineage")},
          ].map((a,i,arr)=>(
            <button key={i} onClick={a.fn}
              style={{width:"100%",display:"flex",alignItems:"center",justifyContent:"space-between",padding:"8px 0",background:"none",border:"none",borderBottom:i<arr.length-1?`1px solid ${T.border}`:"none",color:T.textSub,fontSize:12.5,cursor:"pointer",transition:"color .1s"}}
              onMouseEnter={e=>e.currentTarget.style.color=T.accent} onMouseLeave={e=>e.currentTarget.style.color=T.textSub}>
              {a.l}
              <svg width="9" height="9" viewBox="0 0 10 10" fill="none"><path d="M3 2l4 3-4 3" stroke="currentColor" strokeWidth="1.3" strokeLinecap="round"/></svg>
            </button>
          ))}
        </div>

      </div>
    </div>

    {/* Certification Modal */}
    <Modal open={certModal} onClose={()=>setCertModal(false)} title={`Certify "${asset.name}"`}>
      <p style={{fontSize:13,color:T.textSub,marginBottom:16}}>Certifying marks this asset as trusted and production-ready. This action is logged and visible to all users.</p>
      <div style={{display:"flex",flexDirection:"column",gap:12}}>
        {[
          {label:"Schema documented",done:true},
          {label:"PII columns tagged",done:true},
          {label:"Data lineage verified",done:true},
          {label:"Quality rules passing",done:data.quality>=85},
          {label:"Owner assigned",done:true},
          {label:"Retention policy applied",done:false},
        ].map((c,i)=>(
          <div key={i} style={{display:"flex",alignItems:"center",gap:10,padding:"8px 12px",background:c.done?T.accentDim:T.bgElevated,border:`1px solid ${c.done?"rgba(238,36,36,0.2)":T.border}`,borderRadius:8}}>
            <span style={{color:c.done?T.accent:T.textMuted}}>{c.done?Ic.check(14):Ic.x(14)}</span>
            <span style={{fontSize:13,color:c.done?T.text:T.textSub}}>{c.label}</span>
            {!c.done&&<span style={{fontSize:11,color:T.amber,marginLeft:"auto"}}>Required</span>}
          </div>
        ))}
      </div>
      <div style={{marginTop:16}}>
        <div style={{fontSize:12,color:T.textSub,marginBottom:6}}>Certification notes</div>
        <Input2 multiline rows={3} placeholder="Add notes for the certification record…" value={certNote} onChange={e=>setCertNote(e.target.value)}/>
      </div>
      <div style={{display:"flex",gap:8,marginTop:20,justifyContent:"flex-end"}}>
        <Btn onClick={()=>setCertModal(false)}>Cancel</Btn>
        <Btn variant="primary" icon={Ic.cert(13)} onClick={handleCertify}>Certify Asset</Btn>
      </div>
    </Modal>
  </div>;
};
// ─────────────────────────────────────────────
// CATALOG VIEW
// ─────────────────────────────────────────────
const CatalogView = ({onAsset})=>{
  const tagCtx = useTagCtx();
  const [q,         setQ]         = useState("");
  const [view,      setView]      = useState("table");
  const [sortBy,    setSortBy]    = useState("relevance");
  const [panelOpen, setPanelOpen] = useState(true);
  const [selConnTypes,setSelConnTypes]= useState(new Set());
  const [selTypes,   setSelTypes]   = useState(new Set());
  const [selDomains, setSelDomains] = useState(new Set());
  const [selCerts,   setSelCerts]   = useState(new Set());
  const [selTiers,   setSelTiers]   = useState(new Set());
  const [selConns,   setSelConns]   = useState(new Set());
  const [selOwners,  setSelOwners]  = useState(new Set());
  const [selTags,          setSelTags]          = useState(new Set());
  const [selGlossaryTerms, setSelGlossaryTerms] = useState(new Set());
  const [openGroup,  setOpenGroup]  = useState({conntype:true,connection:false,domain:true,type:false,cert:false,tier:false,owner:false,tags:false,glossary:false});

  const toggle = (setter, val) => setter(prev => { const next = new Set(prev); next.has(val)?next.delete(val):next.add(val); return next; });
  const sorts = [{v:"relevance",l:"Relevance"},{v:"quality",l:"Quality ↓"},{v:"name",l:"Name A–Z"},{v:"updated",l:"Recently Updated"},{v:"usage",l:"Popularity"}];

  const filtered = ASSETS.filter(a => {
    const mq  = !q || a.name.toLowerCase().includes(q.toLowerCase()) || a.domain.toLowerCase().includes(q.toLowerCase()) || a.tags.some(t=>t.toLowerCase().includes(q.toLowerCase())) || a.description.toLowerCase().includes(q.toLowerCase());
    const mct = selConnTypes.size===0 || selConnTypes.has(a.service);
    const mt  = selTypes.size===0   || selTypes.has(a.type);
    const md  = selDomains.size===0 || selDomains.has(a.domain);
    const mc  = selCerts.size===0   || selCerts.has(a.cert);
    const mti = selTiers.size===0   || selTiers.has(String(a.tier));
    const ms  = selConns.size===0   || selConns.has(a.connectionLabel);
    const mo  = selOwners.size===0  || selOwners.has(a.owner);
    const mTag= selTags.size===0    || (a.tags||[]).some(t=>selTags.has(t));
    const mGT = selGlossaryTerms.size===0 || GLOSSARY_TERMS.filter(t=>selGlossaryTerms.has(t.id)).some(t=>(t.linkedAssets||[]).some(la=>la.name===a.name));
    return mq&&mct&&mt&&md&&mc&&mti&&ms&&mo&&mTag&&mGT;
  }).sort((a,b)=>{
    if(sortBy==="quality") return b.quality-a.quality;
    if(sortBy==="name")    return a.name.localeCompare(b.name);
    if(sortBy==="usage")   return (b.usage==="High"?2:b.usage==="Med"?1:0)-(a.usage==="High"?2:a.usage==="Med"?1:0);
    return 0;
  });

  const totalActive = selConnTypes.size+selTypes.size+selDomains.size+selCerts.size+selTiers.size+selConns.size+selOwners.size+selTags.size+selGlossaryTerms.size;
  const clearAll = () => { setSelConnTypes(new Set()); setSelTypes(new Set()); setSelDomains(new Set()); setSelCerts(new Set()); setSelTiers(new Set()); setSelConns(new Set()); setSelOwners(new Set()); setSelTags(new Set()); setSelGlossaryTerms(new Set()); };
  const countFor = (field, val) => ASSETS.filter(a => {
    const mq = !q || a.name.toLowerCase().includes(q.toLowerCase());
    if(!mq) return false;
    if(field==="conntype")   return a.service===val;
    if(field==="type")       return a.type===val;
    if(field==="domain")     return a.domain===val;
    if(field==="cert")       return a.cert===val;
    if(field==="tier")       return String(a.tier)===val;
    if(field==="connection") return a.connectionLabel===val;
    if(field==="owner")      return a.owner===val;
    if(field==="glossary")   return (GLOSSARY_TERMS.find(t=>t.id===val)?.linkedAssets||[]).some(la=>la.name===a.name);
    return false;
  }).length;

  const CERT_COLORS = {"Approved":"#16a34a","In Review":"#d97706","Draft":"#6b7280","Rejected":"#e11d48","Deprecated":"#7c3aed"};
  const TIER_META   = {"1":{color:"#ee2424",label:"Critical"},"2":{color:"#d97706",label:"Important"},"3":{color:"#4b4b60",label:"Exploratory"}};
  const CONN_TYPE_LABELS = {snowflake:"Snowflake",postgres:"PostgreSQL",looker:"Looker",tableau:"Tableau",airflow:"Airflow",mlflow:"MLflow"};
  const allConnTypes = [...new Set(ASSETS.map(a=>a.service))];
  const visibleConns = selConnTypes.size===0 ? [...new Set(ASSETS.map(a=>a.connectionLabel))] : [...new Set(ASSETS.filter(a=>selConnTypes.has(a.service)).map(a=>a.connectionLabel))];

  const FacetGroup = ({id,label,icon,items,sel,onToggle,renderItem,headerNote}) => {
    const open = openGroup[id];
    return (
      <div style={{borderBottom:`1px solid ${T.border}`}}>
        <button onClick={()=>setOpenGroup(p=>({...p,[id]:!p[id]}))} style={{width:"100%",display:"flex",alignItems:"center",gap:8,padding:"9px 14px",background:"transparent",border:"none",cursor:"pointer",textAlign:"left"}}
          onMouseEnter={e=>e.currentTarget.style.background=T.bgHover} onMouseLeave={e=>e.currentTarget.style.background="transparent"}>
          <span style={{color:T.textMuted,display:"flex"}}>{icon}</span>
          <span style={{flex:1,fontSize:11.5,fontWeight:600,color:T.text}}>{label}</span>
          {sel.size>0&&<span style={{fontSize:9.5,fontWeight:700,padding:"1px 5px",borderRadius:99,background:T.accentDim,color:T.accent,border:`1px solid ${T.accent}33`}}>{sel.size}</span>}
          <svg width="10" height="10" viewBox="0 0 10 10" fill="none" style={{color:T.textMuted,transform:open?"none":"rotate(-90deg)",transition:"transform .15s"}}><path d="M1.5 3.5l3.5 3.5 3.5-3.5" stroke="currentColor" strokeWidth="1.4" strokeLinecap="round"/></svg>
        </button>
        {open&&(
          <div style={{padding:"2px 0 6px"}}>
            {headerNote&&<div style={{padding:"3px 14px 5px",fontSize:10,color:T.textMuted,fontStyle:"italic"}}>{headerNote}</div>}
            {items.length===0&&<div style={{padding:"4px 14px",fontSize:11,color:T.textMuted}}>No connections available</div>}
            {items.map(item=>{
              const active = sel.has(item.val);
              return (
                <button key={item.val} onClick={()=>onToggle(item.val)} style={{width:"100%",display:"flex",alignItems:"center",gap:8,padding:"5px 14px 5px 20px",background:active?T.accentDim:"transparent",border:"none",cursor:"pointer",transition:"background .1s"}}
                  onMouseEnter={e=>{if(!active)e.currentTarget.style.background=T.bgHover;}} onMouseLeave={e=>{if(!active)e.currentTarget.style.background="transparent";}}>
                  <div style={{width:13,height:13,borderRadius:3,flexShrink:0,display:"flex",alignItems:"center",justifyContent:"center",background:active?T.accent:"transparent",border:`1.5px solid ${active?T.accent:T.borderLight}`,transition:"all .12s"}}>
                    {active&&<svg width="7" height="7" viewBox="0 0 8 8" fill="none"><path d="M1 4l2 2.5L7 1.5" stroke="white" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/></svg>}
                  </div>
                  <span style={{flex:1,fontSize:11.5,color:active?T.text:T.textSub,fontWeight:active?600:400}}>{renderItem?renderItem(item):item.label}</span>
                  <span style={{fontSize:10.5,color:active?T.accent:T.textMuted,fontWeight:active?700:400}}>{countFor(id,item.val)}</span>
                </button>
              );
            })}
            {sel.size>0&&<button onClick={()=>onToggle(null,"clear")} style={{width:"100%",padding:"2px 14px 2px 20px",background:"transparent",border:"none",cursor:"pointer",textAlign:"left",fontSize:10.5,color:T.textMuted}}
              onMouseEnter={e=>e.currentTarget.style.color=T.rose} onMouseLeave={e=>e.currentTarget.style.color=T.textMuted}>Clear</button>}
          </div>
        )}
      </div>
    );
  };

  const activeChips = [
    ...[...selConnTypes].map(v=>({label:CONN_TYPE_LABELS[v]||v,clear:()=>toggle(setSelConnTypes,v)})),
    ...[...selTypes].map(v=>({label:v,clear:()=>toggle(setSelTypes,v)})),
    ...[...selDomains].map(v=>({label:v,clear:()=>toggle(setSelDomains,v)})),
    ...[...selCerts].map(v=>({label:v,clear:()=>toggle(setSelCerts,v)})),
    ...[...selTiers].map(v=>({label:`Tier ${v}`,clear:()=>toggle(setSelTiers,v)})),
    ...[...selConns].map(v=>({label:v,clear:()=>toggle(setSelConns,v)})),
    ...[...selOwners].map(v=>({label:v,clear:()=>toggle(setSelOwners,v)})),
    ...[...selTags].map(v=>({label:v,clear:()=>toggle(setSelTags,v)})),
    ...[...selGlossaryTerms].map(v=>({label:GLOSSARY_TERMS.find(t=>t.id===v)?.term||v,clear:()=>toggle(setSelGlossaryTerms,v)})),
  ];

  const cols=[
    {key:"name",label:"Asset Name",render:(v,r)=>(
      <div style={{display:"flex",alignItems:"center",gap:10}}>
        <ServiceIcon service={r.service} size={18}/>
        <div><div style={{fontSize:13,fontWeight:500,color:T.text,fontFamily:"'Geist Mono',monospace"}}>{v}</div><div style={{fontSize:10,color:T.textMuted,marginTop:1}}>{r.db}</div></div>
      </div>
    )},
    {key:"type",label:"Type",render:v=><TypeBadge type={v}/>},
    {key:"tier",label:"Tier",render:v=><TierBadge tier={v}/>},
    {key:"domain",label:"Domain",render:v=><span style={{fontSize:12,color:T.textSub}}>{v}</span>},
    {key:"owner",label:"Owner",render:v=><span style={{fontSize:12,color:T.textMuted,fontFamily:"'Geist Mono',monospace"}}>{v}</span>},
    {key:"cert",label:"Certification",render:v=><CertBadge cert={v}/>},
    {key:"quality",label:"Quality",render:v=><QScore score={v}/>},
    {key:"usage",label:"Usage",render:v=><Badge color={v==="High"?T.accent:v==="Med"?T.amber:T.textMuted}>{v}</Badge>},
    {key:"updated",label:"Updated",render:v=><span style={{fontSize:11,color:T.textMuted}}>{v}</span>},
  ];

  return (
    <div className="fadeUp" style={{height:"100%",display:"flex",flexDirection:"column"}}>
      <Topbar breadcrumb={[{label:"Data Catalog"}]}/>
      <div style={{flex:1,display:"flex",overflow:"hidden"}}>
        {/* Filter panel */}
        <div style={{width:panelOpen?212:0,minWidth:panelOpen?212:0,flexShrink:0,overflow:"hidden",borderRight:`1px solid ${T.border}`,background:T.bgSurface,display:"flex",flexDirection:"column",transition:"width .2s ease,min-width .2s ease"}}>
          <div style={{padding:"11px 14px 9px",borderBottom:`1px solid ${T.border}`,display:"flex",alignItems:"center",justifyContent:"space-between",flexShrink:0}}>
            <div style={{display:"flex",alignItems:"center",gap:6}}>{Ic.filter(12)}<span style={{fontSize:11.5,fontWeight:700,color:T.text}}>Filters</span>{totalActive>0&&<span style={{fontSize:9.5,fontWeight:700,padding:"1px 5px",borderRadius:99,background:T.accentDim,color:T.accent,border:`1px solid ${T.accent}33`}}>{totalActive}</span>}</div>
            {totalActive>0&&<button onClick={clearAll} style={{fontSize:11,color:T.textMuted,background:"none",border:"none",cursor:"pointer"}} onMouseEnter={e=>e.currentTarget.style.color=T.rose} onMouseLeave={e=>e.currentTarget.style.color=T.textMuted}>Clear all</button>}
          </div>
          <div style={{flex:1,overflowY:"auto"}}>
            <FacetGroup id="conntype" label="Connector Type" icon={Ic.plug(11)}
              items={allConnTypes.map(v=>({val:v,label:CONN_TYPE_LABELS[v]||v}))}
              sel={selConnTypes} onToggle={(v,c)=>c?setSelConnTypes(new Set()):toggle(setSelConnTypes,v)}
              renderItem={item=><div style={{display:"flex",alignItems:"center",gap:6}}><ServiceIcon service={item.val} size={13}/><span style={{fontSize:11.5,color:T.textSub}}>{item.label}</span></div>}/>
            <FacetGroup id="connection" label="Connection" icon={Ic.branches(11)}
              items={visibleConns.map(v=>({val:v,label:v,svc:ASSETS.find(a=>a.connectionLabel===v)?.service}))}
              sel={selConns} onToggle={(v,c)=>c?setSelConns(new Set()):toggle(setSelConns,v)}
              renderItem={item=><div style={{display:"flex",alignItems:"center",gap:6}}><ServiceIcon service={item.svc} size={13}/><span style={{fontSize:11,color:T.textSub,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{item.label}</span></div>}
              headerNote={selConnTypes.size>0?`Filtered by ${selConnTypes.size} type${selConnTypes.size>1?"s":""}`:null}/>
            <FacetGroup id="domain" label="Domain" icon={Ic.domain(11)}
              items={[...new Set(ASSETS.map(a=>a.domain))].map(v=>({val:v,label:v}))}
              sel={selDomains} onToggle={(v,c)=>c?setSelDomains(new Set()):toggle(setSelDomains,v)}/>
            <FacetGroup id="type" label="Asset Type" icon={Ic.catalog(11)}
              items={["Table","Dashboard","Pipeline","ML Model"].map(v=>({val:v,label:v}))}
              sel={selTypes} onToggle={(v,c)=>c?setSelTypes(new Set()):toggle(setSelTypes,v)}/>
            <FacetGroup id="cert" label="Certification" icon={Ic.cert(11)}
              items={["Approved","In Review","Draft","Rejected","Deprecated"].map(v=>({val:v,label:v}))}
              sel={selCerts} onToggle={(v,c)=>c?setSelCerts(new Set()):toggle(setSelCerts,v)}
              renderItem={item=><span style={{color:CERT_COLORS[item.val]||T.textSub,fontSize:11.5}}>{item.label}</span>}/>
            <FacetGroup id="tier" label="Tier" icon={Ic.shield(11)}
              items={["1","2","3"].map(v=>({val:v,label:v,...TIER_META[v]}))}
              sel={selTiers} onToggle={(v,c)=>c?setSelTiers(new Set()):toggle(setSelTiers,v)}
              renderItem={item=><div style={{display:"flex",alignItems:"center",gap:6}}><span style={{fontSize:9,fontWeight:700,padding:"1px 5px",borderRadius:3,background:`${item.color}18`,color:item.color,border:`1px solid ${item.color}33`}}>T{item.val}</span><span style={{fontSize:11,color:T.textSub}}>{item.label}</span></div>}/>
            <FacetGroup id="owner" label="Owner" icon={Ic.access(11)}
              items={[...new Set(ASSETS.map(a=>a.owner))].map(v=>({val:v,label:v}))}
              sel={selOwners} onToggle={(v,c)=>c?setSelOwners(new Set()):toggle(setSelOwners,v)}
              renderItem={item=><div style={{display:"flex",alignItems:"center",gap:6}}><div style={{width:15,height:15,borderRadius:3,background:T.accentDim,border:`1px solid ${T.accent}33`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:6,fontWeight:700,color:T.accent,flexShrink:0}}>{item.val.split(".").map(s=>s[0].toUpperCase()).join("")}</div><span style={{fontSize:11,color:T.textSub}}>{item.label}</span></div>}/>
            <FacetGroup id="tags" label="Tags" icon={Ic.tag(11)}
              items={[...new Set(ASSETS.flatMap(a=>a.tags||[]))].sort().map(v=>({val:v,label:v}))}
              sel={selTags} onToggle={(v,c)=>c?setSelTags(new Set()):toggle(setSelTags,v)}
              renderItem={item=><div style={{display:"flex",alignItems:"center",gap:6}}><span style={{width:7,height:7,borderRadius:"50%",background:T.accent,display:"block",flexShrink:0,opacity:.7}}/><span style={{fontSize:11,color:T.textSub}}>{item.label}</span></div>}/>
            <FacetGroup id="glossary" label="Business Glossary" icon={Ic.glossary(11)}
              items={GLOSSARY_TERMS.map(t=>({val:t.id,label:t.term,abbr:t.abbr,status:t.status}))}
              sel={selGlossaryTerms} onToggle={(v,c)=>c?setSelGlossaryTerms(new Set()):toggle(setSelGlossaryTerms,v)}
              renderItem={item=>(
                <div style={{display:'flex',alignItems:'center',gap:6,minWidth:0}}>
                  <span style={{flex:1,fontSize:11,color:T.textSub,overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{item.label}</span>
                  {item.abbr&&item.abbr!=='—'&&<span style={{fontSize:9.5,color:T.textMuted,fontFamily:"'Geist Mono',monospace",flexShrink:0}}>{item.abbr}</span>}
                </div>
              )}/>
          </div>
        </div>

        {/* Results */}
        <div style={{flex:1,display:"flex",flexDirection:"column",overflow:"hidden",minWidth:0}}>
          <div style={{padding:"8px 16px",borderBottom:`1px solid ${T.border}`,display:"flex",gap:8,alignItems:"center",flexShrink:0,background:T.bgSurface}}>
            {/* Filter toggle — icon only */}
            <button onClick={()=>setPanelOpen(v=>!v)} title={panelOpen?"Hide filters":"Show filters"}
              style={{width:32,height:32,borderRadius:7,background:panelOpen?T.accentDim:"transparent",border:`1px solid ${panelOpen?T.accent+"66":T.border}`,color:panelOpen?T.accent:T.textMuted,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0,transition:"all .15s",position:"relative"}}
              onMouseEnter={e=>{if(!panelOpen){e.currentTarget.style.background=T.bgHover;e.currentTarget.style.borderColor=T.borderLight;}}}
              onMouseLeave={e=>{if(!panelOpen){e.currentTarget.style.background="transparent";e.currentTarget.style.borderColor=T.border;}}}>
              {Ic.filter(13)}
              {totalActive>0&&<span style={{position:"absolute",top:-4,right:-4,width:14,height:14,borderRadius:"50%",background:T.accent,color:"#fff",fontSize:8,fontWeight:700,display:"flex",alignItems:"center",justifyContent:"center"}}>{totalActive}</span>}
            </button>
            {/* Search */}
            <div style={{flex:1}}><Input2 placeholder="Search assets, descriptions, owners…" value={q} onChange={e=>setQ(e.target.value)} icon={Ic.search(12)}/></div>
            {/* Sort dropdown */}
            <div style={{display:"flex",alignItems:"center",gap:6,flexShrink:0}}>
              <span style={{fontSize:11,color:T.textMuted,whiteSpace:"nowrap"}}>Sort</span>
              <select value={sortBy} onChange={e=>setSortBy(e.target.value)}
                style={{padding:"5px 28px 5px 10px",borderRadius:7,background:T.bgElevated,border:`1px solid ${T.border}`,color:T.text,fontSize:12,outline:"none",cursor:"pointer",appearance:"none",backgroundImage:`url("data:image/svg+xml,%3Csvg width='10' height='6' viewBox='0 0 10 6' fill='none' xmlns='http://www.w3.org/2000/svg'%3E%3Cpath d='M1 1l4 4 4-4' stroke='%236b7280' stroke-width='1.5' stroke-linecap='round' stroke-linejoin='round'/%3E%3C/svg%3E")`,backgroundRepeat:"no-repeat",backgroundPosition:"right 8px center"}}>
                {sorts.map(s=><option key={s.v} value={s.v}>{s.l}</option>)}
              </select>
            </div>
            {/* View toggle — table / card */}
            <div style={{display:"flex",borderRadius:7,border:`1px solid ${T.border}`,overflow:"hidden",flexShrink:0}}>
              {[
                {v:"table",icon:<svg width="13" height="13" viewBox="0 0 14 14" fill="none"><rect x="1" y="1" width="12" height="2.5" rx=".8" fill="currentColor"/><rect x="1" y="5.25" width="12" height="2.5" rx=".8" fill="currentColor" opacity=".5"/><rect x="1" y="9.5" width="12" height="2.5" rx=".8" fill="currentColor" opacity=".25"/></svg>},
                {v:"card", icon:<svg width="13" height="13" viewBox="0 0 14 14" fill="none"><rect x="1" y="1" width="5.5" height="5.5" rx="1" fill="currentColor"/><rect x="7.5" y="1" width="5.5" height="5.5" rx="1" fill="currentColor" opacity=".5"/><rect x="1" y="7.5" width="5.5" height="5.5" rx="1" fill="currentColor" opacity=".5"/><rect x="7.5" y="7.5" width="5.5" height="5.5" rx="1" fill="currentColor" opacity=".25"/></svg>},
              ].map(btn=>(
                <button key={btn.v} onClick={()=>setView(btn.v)} title={btn.v==="table"?"Table view":"Card view"}
                  style={{padding:"6px 9px",border:"none",background:view===btn.v?T.accent:"transparent",color:view===btn.v?"#fff":T.textMuted,cursor:"pointer",display:"flex",alignItems:"center",transition:"all .15s"}}
                  onMouseEnter={e=>{if(view!==btn.v)e.currentTarget.style.background=T.bgHover;}}
                  onMouseLeave={e=>{if(view!==btn.v)e.currentTarget.style.background="transparent";}}>
                  {btn.icon}
                </button>
              ))}
            </div>
            {/* Result count */}
            <span style={{fontSize:11,color:T.textMuted,whiteSpace:"nowrap",flexShrink:0,fontFamily:"'Geist Mono',monospace"}}><b style={{color:T.text}}>{filtered.length}</b>/{ASSETS.length}</span>
          </div>
          {activeChips.length>0&&(
            <div style={{padding:"6px 20px",borderBottom:`1px solid ${T.border}`,display:"flex",gap:5,flexWrap:"wrap",alignItems:"center",background:T.bgElevated,flexShrink:0}}>
              {activeChips.map((f,i)=>(
                <span key={i} style={{display:"inline-flex",alignItems:"center",gap:4,fontSize:11,padding:"2px 7px",borderRadius:99,background:T.accentDim,border:`1px solid ${T.accent}33`,color:T.accent}}>
                  {f.label}<button onClick={f.clear} style={{background:"none",border:"none",color:T.accent,cursor:"pointer",display:"flex",padding:0,opacity:.65,lineHeight:1}}><svg width="8" height="8" viewBox="0 0 10 10" fill="none"><path d="M1.5 1.5l7 7M8.5 1.5l-7 7" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round"/></svg></button>
                </span>
              ))}
              <button onClick={clearAll} style={{fontSize:10.5,color:T.textMuted,background:"none",border:"none",cursor:"pointer",marginLeft:2}} onMouseEnter={e=>e.currentTarget.style.color=T.rose} onMouseLeave={e=>e.currentTarget.style.color=T.textMuted}>Clear all</button>
            </div>
          )}
          <div style={{flex:1,overflowY:"auto",padding:"18px 20px"}}>
            {filtered.length===0&&<div style={{display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",height:200,gap:8}}><div style={{color:T.textMuted,opacity:.25}}>{Ic.catalog(36)}</div><div style={{fontSize:13,fontWeight:600,color:T.textSub}}>No assets match your filters</div><button onClick={clearAll} style={{fontSize:12,color:T.accent,background:"none",border:"none",cursor:"pointer"}}>Clear all filters</button></div>}
            {view==="table"&&filtered.length>0&&<DataTable cols={cols} rows={filtered} onRowClick={r=>onAsset(r)}/>}
            {view==="card"&&filtered.length>0&&(
              <div style={{display:"flex",flexDirection:"column",gap:8}}>
                {filtered.map(a=>{
                  // Find glossary terms linked to this asset
                  const linkedTerms = GLOSSARY_TERMS.filter(t=>(t.linkedAssets||[]).some(la=>la.name===a.name)&&t.status!=="Deprecated");
                  const conflictTerms = linkedTerms.filter(t=>t.conflictFlag);
                  return (
                    <div key={a.id} style={{background:T.bgSurface,border:`1px solid ${conflictTerms.length>0?"rgba(217,119,6,.35)":T.border}`,borderRadius:10,cursor:"pointer",transition:"all .15s",overflow:"hidden"}}
                      onMouseEnter={e=>{e.currentTarget.style.borderColor=conflictTerms.length>0?"rgba(217,119,6,.5)":T.accent+"55";e.currentTarget.style.background=T.bgHover;}}
                      onMouseLeave={e=>{e.currentTarget.style.borderColor=conflictTerms.length>0?"rgba(217,119,6,.35)":T.border;e.currentTarget.style.background=T.bgSurface;}}>
                      <div onClick={()=>onAsset(a)} style={{display:"flex",alignItems:"center",gap:16,padding:"14px 16px"}}>
                        <ServiceIcon service={a.service} size={32}/>
                        <div style={{flex:"0 0 280px",minWidth:0}}>
                          <div style={{display:"flex",alignItems:"center",gap:6,marginBottom:2}}><span style={{fontSize:13.5,fontWeight:700,color:T.text,fontFamily:"'Geist Mono',monospace",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{a.name}</span></div>
                          <div style={{fontSize:10,color:T.textMuted,marginBottom:4,letterSpacing:"0.02em",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{a.db}</div>
                          <div style={{fontSize:11.5,color:T.textSub,lineHeight:1.45,overflow:"hidden",display:"-webkit-box",WebkitLineClamp:1,WebkitBoxOrient:"vertical"}}>{a.description}</div>
                        </div>
                        <div style={{display:"flex",alignItems:"center",gap:7,flex:1,flexWrap:"wrap",minWidth:0}}>
                          <TypeBadge type={a.type}/><TierBadge tier={a.tier}/><CertBadge cert={a.cert}/>
                          <span style={{fontSize:10.5,color:T.textMuted,background:T.bgElevated,padding:"1px 7px",borderRadius:99,border:`1px solid ${T.border}`}}>{a.domain}</span>
                          {a.tags.map(t=><span key={t} style={{fontSize:10,padding:"1px 6px",borderRadius:99,background:t==="PII"?T.roseDim:T.bgHover,color:t==="PII"?T.rose:T.textMuted,border:`1px solid ${t==="PII"?"rgba(253,164,175,.25)":T.border}`}}>{t}</span>)}
                        </div>
                        <div style={{display:"flex",alignItems:"center",gap:16,flexShrink:0}}>
                          <div style={{textAlign:"center",width:40}}><div style={{fontSize:15,fontWeight:700,color:a.quality>=90?T.accent:a.quality>=70?T.amber:T.rose,fontFamily:"'Geist Mono',monospace",lineHeight:1}}>{a.quality}</div><div style={{fontSize:9,color:T.textMuted,marginTop:2}}>quality</div></div>
                          <div title={a.owner} style={{width:22,height:22,borderRadius:6,background:T.accentDim,border:`1px solid ${T.accent}33`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:7.5,fontWeight:700,color:T.accent}}>{a.owner.split(".").map(s=>s[0].toUpperCase()).join("")}</div>
                          <span style={{fontSize:11,color:T.textMuted,whiteSpace:"nowrap",minWidth:50,textAlign:"right"}}>{a.updated}</span>
                          <span style={{color:T.textMuted,opacity:.4}}>{Ic.chevRight(12)}</span>
                        </div>
                      </div>
                      {/* Glossary term pills — contextual glossary */}
                      {linkedTerms.length>0&&(
                        <div style={{padding:"0 16px 10px",display:"flex",alignItems:"center",gap:6,flexWrap:"wrap",borderTop:`1px solid ${T.border}`,paddingTop:8,marginTop:0}}>
                          <span style={{fontSize:10,fontWeight:700,color:T.textMuted,textTransform:"uppercase",letterSpacing:"0.07em",flexShrink:0}}>Glossary:</span>
                          {linkedTerms.map(t=>{
                            const cm=CERT_META[t.cert]||CERT_META.Draft;
                            return (
                              <span key={t.id} title={t.definition||t.term} style={{display:"inline-flex",alignItems:"center",gap:4,fontSize:11,padding:"2px 8px",borderRadius:99,background:t.conflictFlag?"rgba(217,119,6,.1)":cm.bg,color:t.conflictFlag?"#d97706":cm.color,border:`1px solid ${t.conflictFlag?"rgba(217,119,6,.3)":cm.border}`,fontWeight:600,cursor:"default"}}>
                                {t.conflictFlag&&<span>⚡</span>}{cm.icon} {t.term}{t.abbr&&t.abbr!=="—"&&<span style={{fontWeight:400,opacity:.7}}> ({t.abbr})</span>}
                              </span>
                            );
                          })}
                          {conflictTerms.length>0&&<span style={{fontSize:10.5,color:"#d97706",fontWeight:600}}>⚡ Conflict detected</span>}
                        </div>
                      )}
                    </div>
                  );
                })}
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

// ─────────────────────────────────────────────
// DATA CONTRACTS
// ─────────────────────────────────────────────
const ContractsView = ({onToast})=>{
  const [selected,setSelected]=useState(null);
  if(selected) return <ContractDetail contract={selected} onBack={()=>setSelected(null)} onToast={onToast}/>;
  return <div className="fadeUp" style={{height:"100%",display:"flex",flexDirection:"column"}}>
    <Topbar breadcrumb={[{label:"Data Contracts"}]}/>
    <div style={{flex:1,overflowY:"auto",padding:28}}>
      <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:12,marginBottom:24}}>
        {[
          {label:"Active Contracts",value:String(CONTRACTS.filter(c=>c.status==="Active").length),color:"#16a34a"},
          {label:"Deprecated",      value:String(CONTRACTS.filter(c=>c.status==="Deprecated").length),color:T.rose},
          {label:"Avg SLA",         value:"99.3%",color:T.accent},
          {label:"Owners",          value:String(new Set(CONTRACTS.flatMap(c=>c.owners)).size),color:"#60a5fa"},
        ].map((m,i)=><Metric key={i} label={m.label} value={m.value} color={m.color}/>)}
      </div>
      <div style={{display:"flex",justifyContent:"flex-end",marginBottom:14}}>
        <Btn icon={Ic.plus(12)} variant="primary" onClick={()=>onToast("Contract wizard opened","success")}>New Contract</Btn>
      </div>
      <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:12}}>
        {CONTRACTS.map(c=>(
          <div key={c.id} onClick={()=>setSelected(c)} style={{padding:18,background:T.bgSurface,border:`1px solid ${c.status==="Deprecated"?T.rose+"33":T.border}`,borderRadius:12,cursor:"pointer",transition:"all .15s"}}
            onMouseEnter={e=>{e.currentTarget.style.borderColor=T.accent+"55";e.currentTarget.style.transform="translateY(-1px)";}}
            onMouseLeave={e=>{e.currentTarget.style.borderColor=c.status==="Deprecated"?T.rose+"33":T.border;e.currentTarget.style.transform="none";}}>
            <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:8}}>
              <span style={{fontSize:14,fontWeight:700,color:T.text,fontFamily:"'Geist Mono',monospace"}}>{c.name}</span>
              <Badge color={c.status==="Active"?T.accent:T.rose} bg={c.status==="Active"?T.accentDim:T.roseDim}>{c.status}</Badge>
            </div>
            <div style={{fontSize:12,color:T.textSub,lineHeight:1.5,marginBottom:12}}>{c.description}</div>
            <div style={{display:"flex",flexDirection:"column",gap:5,fontSize:11.5,color:T.textMuted}}>
              <div style={{display:"flex",justifyContent:"space-between"}}><span>Provider</span><span style={{color:T.text,fontFamily:"'Geist Mono',monospace"}}>{c.provider}</span></div>
              <div style={{display:"flex",justifyContent:"space-between"}}><span>Consumer</span><span style={{color:T.text,fontFamily:"'Geist Mono',monospace"}}>{c.consumer}</span></div>
              <div style={{display:"flex",justifyContent:"space-between"}}><span>SLA</span><span style={{color:"#16a34a",fontWeight:600}}>{c.sla}</span></div>
              <div style={{display:"flex",justifyContent:"space-between"}}><span>Version</span><span style={{color:T.text,fontFamily:"'Geist Mono',monospace"}}>{c.version}</span></div>
            </div>
          </div>
        ))}
      </div>
    </div>
  </div>;
};;

const ContractDetail = ({contract,onBack,onToast})=>(
  <div className="fadeUp" style={{height:"100%",display:"flex",flexDirection:"column"}}>
    <Topbar breadcrumb={[{label:"Data Contracts",onClick:onBack},{label:contract.name}]}/>
    <div style={{flex:1,overflowY:"auto",padding:28}}>
      <div style={{display:"flex",justifyContent:"flex-end",gap:8,marginBottom:16}}>
        <Btn small icon={Ic.branches(12)}>New Version</Btn>
        <Btn small ghost>Edit</Btn>
      </div>
      <div style={{display:"grid",gridTemplateColumns:"2fr 1fr",gap:20}}>
        <div style={{display:"flex",flexDirection:"column",gap:16}}>
          <Card2><div style={{padding:16}}>
            <SH title="Contract Definition"/>
            <p style={{fontSize:13,color:T.textSub,marginBottom:14,lineHeight:1.7}}>{contract.description}</p>
            <div style={{background:T.bgHover,borderRadius:8,padding:16,fontFamily:"'Geist Mono',monospace",fontSize:12,color:T.textSub,lineHeight:1.9}}>
              <span style={{color:T.violet}}>contract</span> <span style={{color:T.accent}}>{contract.name}</span> {"{"}<br/>
              &nbsp;&nbsp;<span style={{color:T.violet}}>version</span>: <span style={{color:T.amber}}>"{contract.version}"</span><br/>
              &nbsp;&nbsp;<span style={{color:T.violet}}>provider</span>: <span style={{color:T.amber}}>"{contract.provider}"</span><br/>
              &nbsp;&nbsp;<span style={{color:T.violet}}>consumer</span>: <span style={{color:T.amber}}>"{contract.consumer}"</span><br/>
              &nbsp;&nbsp;<span style={{color:T.violet}}>sla</span>: {"{"} <span style={{color:T.blue}}>availability</span>: <span style={{color:T.amber}}>"{contract.sla}"</span>, <span style={{color:T.blue}}>freshness</span>: <span style={{color:T.amber}}>"2h"</span> {"}"}<br/>
              &nbsp;&nbsp;<span style={{color:T.violet}}>schema</span>: <span style={{color:T.amber}}>"{contract.schema}"</span><br/>
              &nbsp;&nbsp;<span style={{color:T.violet}}>owners</span>: [<span style={{color:T.blue}}>{contract.owners.map(o=>`"${o}"`).join(", ")}</span>]<br/>
              {"}"}
            </div>
          </div></Card2>
          <Card2><div style={{padding:16}}>
            <SH title="Schema Snapshot" action={<Badge color={T.accent} bg={T.accentDim}>v{contract.version}</Badge>}/>
            <div style={{display:"flex",flexDirection:"column",gap:6}}>
              {["id: BIGINT NOT NULL","customer_id: BIGINT","amount: DECIMAL(12,2)","status: ENUM","created_at: TIMESTAMP"].map((f,i)=>(
                <div key={i} style={{padding:"7px 12px",background:T.bgHover,borderRadius:6,fontFamily:"'Geist Mono',monospace",fontSize:12,color:T.textSub}}>{f}</div>
              ))}
            </div>
          </div></Card2>
        </div>
        <div style={{display:"flex",flexDirection:"column",gap:12}}>
          <Card2><div style={{padding:14}}>
            <SH title="Contract Info"/>
            {[{l:"Status",v:<><SDot status={contract.status}/> {contract.status}</>},{l:"Version",v:contract.version},{l:"SLA",v:<span style={{color:T.accent,fontFamily:"'Geist Mono',monospace"}}>{contract.sla}</span>},{l:"Provider",v:<span style={{color:T.amber,fontFamily:"'Geist Mono',monospace"}}>{contract.provider}</span>},{l:"Consumer",v:<span style={{color:T.violet,fontFamily:"'Geist Mono',monospace"}}>{contract.consumer}</span>},{l:"Updated",v:contract.updated}].map(m=>(
              <div key={m.l} style={{display:"flex",justifyContent:"space-between",alignItems:"center",fontSize:12,marginBottom:9}}><span style={{color:T.textMuted}}>{m.l}</span><span style={{color:T.text,display:"flex",alignItems:"center",gap:4}}>{m.v}</span></div>
            ))}
          </div></Card2>
          <Card2><div style={{padding:14}}>
            <SH title="Version History"/>
            {[{v:contract.version,date:"2d ago",status:"Current"},{v:"2.0.2",date:"2w ago",status:"Deprecated"},{v:"1.x",date:"3mo ago",status:"Deprecated"}].map((v,i)=>(
              <div key={i} style={{display:"flex",alignItems:"center",gap:8,padding:"7px 0",borderBottom:i<2?`1px solid ${T.border}`:"none"}}>
                <span style={{fontFamily:"'Geist Mono',monospace",fontSize:12,color:T.text}}>v{v.v}</span>
                <span style={{fontSize:11,color:T.textMuted,flex:1}}>{v.date}</span>
                <Badge color={v.status==="Current"?T.accent:T.textMuted}>{v.status}</Badge>
              </div>
            ))}
          </div></Card2>
        </div>
      </div>
    </div>
  </div>
);

