// LOGIN SCREEN
// ─────────────────────────────────────────────
const LoginScreen = ({onLogin}) => {
  const [email,    setEmail]    = useState("");
  const [password, setPassword] = useState("");
  const [loading,  setLoading]  = useState(false);
  const [error,    setError]    = useState("");
  const [showPw,   setShowPw]   = useState(false);

  // Demo accounts mapped to roles
  const DEMO_ACCOUNTS = {
    "alex.rivera@jnj.com":  {role:"admin",    pw:"admin123"},
    "maya.chen@jnj.com":    {role:"steward",  pw:"steward123"},
    "dev.patel@jnj.com":    {role:"analyst",  pw:"analyst123"},
    "james.oh@jnj.com":     {role:"engineer", pw:"engineer123"},
    "sarah.kim@jnj.com":    {role:"viewer",   pw:"viewer123"},
  };

  const handleSubmit = () => {
    setError("");
    if(!email.trim()) { setError("Email is required"); return; }
    if(!password)     { setError("Password is required"); return; }
    setLoading(true);
    setTimeout(()=>{
      const account = DEMO_ACCOUNTS[email.toLowerCase().trim()];
      if(account && account.pw === password) {
        onLogin(account.role);
      } else if(DEMO_ACCOUNTS[email.toLowerCase().trim()]) {
        setError("Incorrect password. Try the demo password shown below.");
        setLoading(false);
      } else {
        setError("No account found with that email.");
        setLoading(false);
      }
    }, 800);
  };

  const quickLogin = (role) => {
    const cfg = ROLES_CONFIG[role];
    setEmail(cfg.email);
    setPassword(DEMO_ACCOUNTS[cfg.email].pw);
    setError("");
  };

  return (
    <div style={{
      minHeight:"100vh", display:"flex", background:T.bg,
      fontFamily:"'Geist',sans-serif",
    }}>
      {/* Left panel — branding */}
      <div style={{
        width:"44%", background:`linear-gradient(145deg,#1a0505 0%,#2d0808 40%,#1a0505 100%)`,
        display:"flex", flexDirection:"column", justifyContent:"space-between",
        padding:"48px 52px", position:"relative", overflow:"hidden",
      }}>
        {/* Decorative circles */}
        <div style={{position:"absolute",top:-120,right:-120,width:400,height:400,borderRadius:"50%",border:"1px solid rgba(238,36,36,0.3)",pointerEvents:"none"}}/>
        <div style={{position:"absolute",top:-60,right:-60,width:250,height:250,borderRadius:"50%",border:"1px solid rgba(238,36,36,0.2)",pointerEvents:"none"}}/>
        <div style={{position:"absolute",bottom:-80,left:-80,width:320,height:320,borderRadius:"50%",border:"1px solid rgba(238,36,36,0.15)",pointerEvents:"none"}}/>

        {/* Logo */}
        <div style={{display:"flex",alignItems:"center",gap:14,position:"relative",zIndex:1}}>
          <div style={{width:40,height:40,borderRadius:"50%",flexShrink:0,overflow:"hidden",boxShadow:"0 0 24px rgba(238,36,36,0.5)"}}>
            <svg width="40" height="40" viewBox="0 0 40 40" fill="none" xmlns="http://www.w3.org/2000/svg">
              <circle cx="20" cy="20" r="20" fill="#ee2424"/>
              <path d="M23 7L13 22h8l-4 11 14-16h-9l1-10z" fill="white"/>
            </svg>
          </div>
          <div>
            <div style={{fontSize:15,fontWeight:700,color:"#f4f4f5",letterSpacing:"-0.3px"}}>Solix</div>
            <div style={{fontSize:11,color:"rgba(255,255,255,0.45)",textTransform:"uppercase",letterSpacing:"0.1em",marginTop:1}}>Data Governance</div>
          </div>
        </div>

        {/* Center content */}
        <div style={{position:"relative",zIndex:1}}>
          <div style={{fontSize:32,fontWeight:700,color:"#f4f4f5",lineHeight:1.2,marginBottom:16,letterSpacing:"-0.5px"}}>
            Trusted data.<br/>
            <span style={{color:"#ee2424"}}>Governed</span> together.
          </div>
          <div style={{fontSize:14,color:"rgba(255,255,255,0.5)",lineHeight:1.7,marginBottom:40}}>
            One platform to discover, govern, and trust your data across every team and domain at Johnson &amp; Johnson.
          </div>
          {/* Feature pills */}
          <div style={{display:"flex",flexDirection:"column",gap:10}}>
            {[
              {icon:Ic.catalog(14), text:"6,724 assets indexed across 5 domains"},
              {icon:Ic.quality(14), text:"87.3% average data quality score"},
              {icon:Ic.compliance(14), text:"GDPR & HIPAA compliance tracked"},
            ].map((f,i)=>(
              <div key={i} style={{display:"flex",alignItems:"center",gap:10,padding:"10px 14px",background:"rgba(255,255,255,0.05)",borderRadius:9,border:"1px solid rgba(255,255,255,0.07)"}}>
                <span style={{color:"#ee2424",display:"flex",flexShrink:0}}>{f.icon}</span>
                <span style={{fontSize:12,color:"rgba(255,255,255,0.6)"}}>{f.text}</span>
              </div>
            ))}
          </div>
        </div>

        <div style={{fontSize:11,color:"rgba(255,255,255,0.25)",position:"relative",zIndex:1}}>
          © 2025 Johnson &amp; Johnson · Powered by Solix
        </div>
      </div>

      {/* Right panel — login form */}
      <div style={{flex:1,display:"flex",alignItems:"center",justifyContent:"center",padding:"40px 60px",overflowY:"auto"}}>
        <div style={{width:"100%",maxWidth:400}}>
          <div style={{marginBottom:32}}>
            <div style={{fontSize:24,fontWeight:700,color:T.text,marginBottom:8,letterSpacing:"-0.4px"}}>Sign in</div>
            <div style={{fontSize:13,color:T.textMuted}}>Access your J&amp;J data governance workspace</div>
          </div>

          {/* Email */}
          <div style={{marginBottom:16}}>
            <label style={{display:"block",fontSize:12,fontWeight:600,color:T.textSub,marginBottom:6}}>Work email</label>
            <input
              type="email" value={email} onChange={e=>{setEmail(e.target.value);setError("");}}
              onKeyDown={e=>e.key==="Enter"&&handleSubmit()}
              placeholder="you@jnj.com"
              style={{width:"100%",padding:"10px 13px",background:T.bgSurface,border:`1.5px solid ${error&&!email?T.rose:T.border}`,borderRadius:9,color:T.text,fontSize:13,outline:"none",boxSizing:"border-box",transition:"border-color .15s"}}
              onFocus={e=>e.target.style.borderColor=T.accent}
              onBlur={e=>e.target.style.borderColor=error&&!email?T.rose:T.border}
            />
          </div>

          {/* Password */}
          <div style={{marginBottom:8}}>
            <div style={{display:"flex",justifyContent:"space-between",marginBottom:6}}>
              <label style={{fontSize:12,fontWeight:600,color:T.textSub}}>Password</label>
              <button style={{background:"none",border:"none",fontSize:12,color:T.accent,cursor:"pointer",padding:0}}>Forgot password?</button>
            </div>
            <div style={{position:"relative"}}>
              <input
                type={showPw?"text":"password"} value={password} onChange={e=>{setPassword(e.target.value);setError("");}}
                onKeyDown={e=>e.key==="Enter"&&handleSubmit()}
                placeholder="••••••••"
                style={{width:"100%",padding:"10px 40px 10px 13px",background:T.bgSurface,border:`1.5px solid ${error&&!password?T.rose:T.border}`,borderRadius:9,color:T.text,fontSize:13,outline:"none",boxSizing:"border-box",transition:"border-color .15s"}}
                onFocus={e=>e.target.style.borderColor=T.accent}
                onBlur={e=>e.target.style.borderColor=error&&!password?T.rose:T.border}
              />
              <button onClick={()=>setShowPw(v=>!v)} style={{position:"absolute",right:10,top:"50%",transform:"translateY(-50%)",background:"none",border:"none",color:T.textMuted,cursor:"pointer",display:"flex",padding:4}}>
                {showPw
                  ? <svg width="15" height="15" viewBox="0 0 16 16" fill="none"><path d="M2 8s2.5-5 6-5 6 5 6 5-2.5 5-6 5-6-5-6-5z" stroke="currentColor" strokeWidth="1.3"/><circle cx="8" cy="8" r="2" stroke="currentColor" strokeWidth="1.3"/><path d="M3 3l10 10" stroke="currentColor" strokeWidth="1.3" strokeLinecap="round"/></svg>
                  : <svg width="15" height="15" viewBox="0 0 16 16" fill="none"><path d="M2 8s2.5-5 6-5 6 5 6 5-2.5 5-6 5-6-5-6-5z" stroke="currentColor" strokeWidth="1.3"/><circle cx="8" cy="8" r="2" stroke="currentColor" strokeWidth="1.3"/></svg>
                }
              </button>
            </div>
          </div>

          {/* Error */}
          {error && (
            <div style={{display:"flex",alignItems:"center",gap:7,padding:"8px 11px",background:T.roseDim,border:`1px solid ${T.rose}44`,borderRadius:7,marginBottom:16,fontSize:12,color:T.rose}}>
              {Ic.alert(12)}{error}
            </div>
          )}

          {/* Sign in button */}
          <button onClick={handleSubmit} disabled={loading} style={{
            width:"100%",padding:"11px",marginTop:8,borderRadius:9,border:"none",
            background:loading?"rgba(238,36,36,0.6)":"#ee2424",
            color:"#fff",fontSize:13,fontWeight:700,cursor:loading?"default":"pointer",
            transition:"all .15s",letterSpacing:"0.01em",
            boxShadow:loading?"none":"0 2px 12px rgba(238,36,36,0.35)",
          }}
            onMouseEnter={e=>{if(!loading)e.currentTarget.style.background="#d41f1f";}}
            onMouseLeave={e=>{if(!loading)e.currentTarget.style.background="#ee2424";}}
          >
            {loading
              ? <span style={{display:"flex",alignItems:"center",justifyContent:"center",gap:8}}>
                  <svg width="14" height="14" viewBox="0 0 14 14" fill="none" style={{animation:"spin 1s linear infinite"}}><circle cx="7" cy="7" r="5.5" stroke="rgba(255,255,255,0.3)" strokeWidth="1.5"/><path d="M7 1.5A5.5 5.5 0 0112.5 7" stroke="#fff" strokeWidth="1.5" strokeLinecap="round"/></svg>
                  Signing in…
                </span>
              : "Sign in"
            }
          </button>

          {/* Divider */}
          <div style={{display:"flex",alignItems:"center",gap:12,margin:"28px 0 20px"}}>
            <div style={{flex:1,height:1,background:T.border}}/>
            <span style={{fontSize:11,color:T.textMuted,fontWeight:500}}>DEMO ACCOUNTS</span>
            <div style={{flex:1,height:1,background:T.border}}/>
          </div>

          {/* Role quick-login cards */}
          <div style={{display:"flex",flexDirection:"column",gap:8}}>
            <div style={{fontSize:11,color:T.textMuted,marginBottom:4}}>
              Click any role to auto-fill credentials and see how the UI adapts:
            </div>
            {Object.entries(ROLES_CONFIG).map(([roleKey, cfg])=>(
              <button key={roleKey} onClick={()=>quickLogin(roleKey)} style={{
                display:"flex",alignItems:"center",gap:12,padding:"10px 13px",
                background:email===cfg.email?cfg.badge:T.bgSurface,
                border:`1.5px solid ${email===cfg.email?cfg.color+"55":T.border}`,
                borderRadius:9,cursor:"pointer",textAlign:"left",transition:"all .15s",width:"100%",
              }}
                onMouseEnter={e=>{if(email!==cfg.email){e.currentTarget.style.background=T.bgHover;e.currentTarget.style.borderColor=T.borderLight;}}}
                onMouseLeave={e=>{if(email!==cfg.email){e.currentTarget.style.background=T.bgSurface;e.currentTarget.style.borderColor=T.border;}}}
              >
                <div style={{width:32,height:32,borderRadius:8,background:cfg.badge,border:`1px solid ${cfg.color}44`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:11,fontWeight:700,color:cfg.color,flexShrink:0}}>
                  {cfg.avatar}
                </div>
                <div style={{flex:1,minWidth:0}}>
                  <div style={{display:"flex",alignItems:"center",gap:7}}>
                    <span style={{fontSize:12,fontWeight:600,color:T.text}}>{cfg.label}</span>
                    <span style={{fontSize:10,color:cfg.color,background:cfg.badge,padding:"1px 6px",borderRadius:4,fontWeight:600}}>{cfg.label}</span>
                  </div>
                  <div style={{fontSize:10.5,color:T.textMuted,marginTop:1,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{cfg.email}</div>
                </div>
                {email===cfg.email && <span style={{color:T.accent,display:"flex",flexShrink:0}}>{Ic.check(12)}</span>}
              </button>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};


