const HEALTH_COLOR = {healthy:"#34d399", running:"#60a5fa", degraded:"#fbbf24", disconnected:"#f87171", warning:"#fbbf24"};
const STATUS_LABEL = {connected:"Connected", running:"Running", warning:"Warning", disconnected:"Disconnected"};

/* shared micro-components */
const SettSH = ({icon,title,desc,action}) => (
  <div style={{display:"flex",alignItems:"flex-start",justifyContent:"space-between",marginBottom:22}}>
    <div style={{display:"flex",alignItems:"center",gap:12}}>
      <div style={{width:34,height:34,borderRadius:9,background:T.accentDim,border:`1px solid ${T.accent}33`,display:"flex",alignItems:"center",justifyContent:"center",color:T.accent,flexShrink:0}}>
        {icon}
      </div>
      <div>
        <div style={{fontSize:15,fontWeight:700,color:T.text}}>{title}</div>
        <div style={{fontSize:12,color:T.textMuted,marginTop:1}}>{desc}</div>
      </div>
    </div>
    {action}
  </div>
);

const Toggle = ({on,onChange,disabled=false}) => (
  <div onClick={disabled?null:onChange} style={{width:36,height:20,borderRadius:10,flexShrink:0,cursor:disabled?"default":"pointer",transition:"background .2s",opacity:disabled?.5:1,
    background:on?T.accent:T.bgHover,border:`1px solid ${on?T.accent:T.border}`,position:"relative"}}>
    <div style={{position:"absolute",width:14,height:14,borderRadius:"50%",background:"#fff",top:2,transition:"left .18s",left:on?18:2,boxShadow:"0 1px 3px rgba(0,0,0,.3)"}}/>
  </div>
);

const AddBtn = ({label,onClick}) => (
  <button onClick={onClick} style={{display:"flex",alignItems:"center",gap:5,padding:"6px 12px",borderRadius:7,background:T.accent,border:"none",color:"#fff",fontSize:12,fontWeight:600,cursor:"pointer"}}
    onMouseEnter={e=>e.currentTarget.style.opacity=".85"} onMouseLeave={e=>e.currentTarget.style.opacity="1"}>
    <svg width="11" height="11" viewBox="0 0 12 12" fill="none"><path d="M6 1v10M1 6h10" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round"/></svg>{label}
  </button>
);

const HealthBadge = ({health,status}) => {
  const c=HEALTH_COLOR[health]||T.textMuted;
  return <span style={{display:"inline-flex",alignItems:"center",gap:4,fontSize:10.5,fontWeight:600,padding:"2px 9px",borderRadius:99,background:`${c}15`,border:`1px solid ${c}33`,color:c}}>
    <span style={{width:5,height:5,borderRadius:"50%",background:c,display:"inline-block"}}/>
    {STATUS_LABEL[status]||status}
  </span>;
};

// ─────────────────────────────────────────────
// SETTINGS HELPER COMPONENTS (top-level to satisfy Rules of Hooks)
// ─────────────────────────────────────────────
const RunRow = ({run}) => {
  const [expanded, setExpanded] = useState(false);
  const sc = run.status==="success"?T.accent:run.status==="failed"?T.rose:run.status==="running"?"#60a5fa":T.amber;
  return (
    <div style={{background:T.bgElevated,border:`1px solid ${run.status==="failed"?T.rose+"44":T.border}`,borderRadius:9,overflow:"hidden"}}>
      <div onClick={()=>setExpanded(v=>!v)} style={{display:"flex",alignItems:"center",gap:10,padding:"10px 12px",cursor:"pointer"}}>
        <span style={{width:8,height:8,borderRadius:"50%",background:sc,flexShrink:0,boxShadow:`0 0 5px ${sc}`}}/>
        <div style={{flex:1}}>
          <div style={{fontSize:12,fontWeight:500,color:T.text}}>{run.ts}</div>
          <div style={{display:"flex",gap:10,fontSize:10,color:T.textMuted,marginTop:2}}>
            {run.duration!=="—"&&<span>{run.duration}</span>}
            {run.records>0&&<span>{run.records.toLocaleString()} rows</span>}
            {run.errors>0&&<span style={{color:T.rose}}>{run.errors} error{run.errors>1?"s":""}</span>}
            {run.warnings>0&&<span style={{color:T.amber}}>{run.warnings} warning{run.warnings>1?"s":""}</span>}
          </div>
        </div>
        <span style={{fontSize:10,fontWeight:700,color:sc,textTransform:"capitalize"}}>{run.status}</span>
        <svg width="10" height="10" viewBox="0 0 10 10" fill="none" style={{transform:expanded?"rotate(180deg)":"none",transition:"transform .2s",color:T.textMuted}}>
          <path d="M2 3.5l3 3 3-3" stroke="currentColor" strokeWidth="1.4" strokeLinecap="round"/>
        </svg>
      </div>
      {expanded&&(run.errorMsg||run.warnMsg)&&(
        <div style={{padding:"0 12px 10px",borderTop:`1px solid ${T.border}`}}>
          <div style={{marginTop:8,padding:"8px 10px",background:run.errorMsg?T.roseDim:T.amberDim,borderRadius:6,fontSize:11,color:run.errorMsg?T.rose:T.amber,fontFamily:"'Geist Mono',monospace"}}>
            {run.errorMsg||run.warnMsg}
          </div>
        </div>
      )}
      {expanded&&run.status==="success"&&(
        <div style={{padding:"0 12px 10px",borderTop:`1px solid ${T.border}`}}>
          <div style={{marginTop:8,display:"flex",gap:12}}>
            {[{l:"Records",v:run.records.toLocaleString()},{l:"Duration",v:run.duration},{l:"Errors",v:run.errors},{l:"Warnings",v:run.warnings}].map(m=>(
              <div key={m.l} style={{textAlign:"center"}}>
                <div style={{fontSize:13,fontWeight:700,color:T.text}}>{m.v}</div>
                <div style={{fontSize:9,color:T.textMuted}}>{m.l}</div>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

